function getStoredConfigKeys() {
const keys = new Set();
try {
if (typeof GM_listValues !== 'undefined') {
const gmKeys = GM_listValues();
if (Array.isArray(gmKeys)) gmKeys.forEach(k => keys.add(k));
}
} catch (e) {}
try {
for (let i = 0; i < localStorage.length; i++) {
const k = localStorage.key(i);
if (k) keys.add(k);
}
} catch (e) {}
return Array.from(keys);
}

function getStoredConfigRaw(key) {
try {
if (typeof GM_getValue !== 'undefined') {
const marker = `__pk_missing_${Date.now()}_${Math.random()}__`;
const v = GM_getValue(key, marker);
if (v !== marker) return v;
}
} catch (e) {}
try {
const v = localStorage.getItem(key);
if (v !== null) return v;
} catch (e) {}
return undefined;
}

function setStoredConfigRaw(key, value) {
if (value === undefined) return removeStoredConfigKey(key);
try { if (typeof GM_setValue !== 'undefined') GM_setValue(key, value); } catch (e) {}
try { localStorage.setItem(key, typeof value === 'string' ? value : JSON.stringify(value)); } catch (e) {}
}

function removeStoredConfigKey(key) {
try { if (typeof GM_deleteValue !== 'undefined') GM_deleteValue(key); } catch (e) {}
try { localStorage.removeItem(key); } catch (e) {}
}

function configValueEquals(a, b) {
if (a === b) return true;
try { return JSON.stringify(a) === JSON.stringify(b); } catch (e) { return String(a) === String(b); }
}

function getConfigEntryRank(key, value, fallbackRank) {
const parsed = parseConfigJson(value, null);
if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
const t = parseConfigTime(parsed.lastUsedAt || parsed.last_used_at || parsed.updatedAt || parsed.updated_at || parsed.savedAt || parsed.saved_at || parsed.checkedAt || parsed.expiresAt || parsed.ts || parsed.time);
if (t) return t;
}
return fallbackRank;
}

function cleanupPrefixKeys(prefix, options = {}) {
const keys = getStoredConfigKeys().filter(k => k.startsWith(prefix));
const entries = [];
keys.forEach((key, index) => {
if (options.maxKeyLen && key.length > prefix.length + options.maxKeyLen) {
removeStoredConfigKey(key);
return;
}
const raw = getStoredConfigRaw(key);
const normalized = normalizeConfigValue(key, raw, 'localWrite');
if (normalized === undefined || (options.removeEmpty && (normalized === '' || normalized === '[]' || normalized === '{}'))) {
removeStoredConfigKey(key);
return;
}
if (!configValueEquals(raw, normalized)) setStoredConfigRaw(key, normalized);
entries.push({ key, value: normalized, rank: getConfigEntryRank(key, normalized, index), size: estimateTextSize(key) + estimateTextSize(typeof normalized === 'string' ? normalized : JSON.stringify(normalized)) });
});
entries.sort((a, b) => b.rank - a.rank);
const keep = new Set();
let total = 0;
const maxItems = options.maxItems || Infinity;
const maxSize = options.maxSize || Infinity;
entries.forEach(entry => {
if (keep.size >= maxItems || total + entry.size > maxSize) return;
keep.add(entry.key);
total += entry.size;
});
entries.forEach(entry => {
if (!keep.has(entry.key)) removeStoredConfigKey(entry.key);
});
}

function cleanupLruPrefixKeys(prefix, options = {}) {
cleanupPrefixKeys(prefix, options);
}

function cleanupTtlPrefixKeys(prefix, options = {}) {
const now = Date.now();
getStoredConfigKeys().filter(k => k.startsWith(prefix)).forEach(key => {
const raw = getStoredConfigRaw(key);
const parsed = parseConfigJson(raw, null);
if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
const expiresAt = parseConfigTime(parsed.expiresAt || parsed.expireAt || parsed.expire_at);
const checkedAt = parseConfigTime(parsed.checkedAt || parsed.updatedAt || parsed.savedAt);
if ((expiresAt && expiresAt < now) || (!expiresAt && checkedAt && options.ttlMs && now - checkedAt > options.ttlMs)) {
removeStoredConfigKey(key);
}
}
});
cleanupPrefixKeys(prefix, options);
}

function cleanupConfigPrefixKeys() {
const captchaSchema = getConfigLimitSchema('pk_captured_captcha');
const captchaRaw = getStoredConfigRaw('pk_captured_captcha');
if (captchaRaw !== undefined && shouldRemoveCapturedCaptchaValue(captchaRaw, (captchaSchema && captchaSchema.localLimit) || {})) {
removeStoredConfigKey('pk_captured_captcha');
}
getStoredConfigKeys().forEach(key => {
if (isCapacityProbeStorageKey(key)) removeStoredConfigKey(key);
});
CONFIG_LIMIT_SCHEMA.entries.filter(entry => entry.key).forEach(entry => {
const raw = getStoredConfigRaw(entry.key);
if (raw === undefined) return;
const normalized = normalizeConfigValue(entry.key, raw, 'localWrite');
if (normalized === undefined || normalized === '') {
if (entry.ttl || entry.type === 'prohibitedProbe') removeStoredConfigKey(entry.key);
return;
}
if (!configValueEquals(raw, normalized)) setStoredConfigRaw(entry.key, normalized);
});
cleanupLruPrefixKeys('pk_archive_pwd_', { maxItems: 1000, maxItemLen: 512, maxSize: 256 * CONFIG_SIZE.KB, removeEmpty: true });
cleanupLruPrefixKeys('pk_duration_', { maxItems: 10000, maxSize: CONFIG_SIZE.MB });
cleanupLruPrefixKeys('pk_scan_last_', { maxItems: 500, maxItemLen: 2048, maxSize: 128 * CONFIG_SIZE.KB });
cleanupLruPrefixKeys('pk_analyze_last_', { maxItems: 500, maxItemLen: 2048, maxSize: 128 * CONFIG_SIZE.KB });
cleanupLruPrefixKeys('pk_fmod_', { maxItems: 5000, maxKeyLen: 128, maxItemLen: 2048, maxSize: 512 * CONFIG_SIZE.KB });
cleanupTtlPrefixKeys('pk_i18n_', { maxSize: 512 * CONFIG_SIZE.KB, ttlMs: 7 * 24 * 60 * 60 * 1000 });
cleanupTtlPrefixKeys('pk_script_update_dismiss_', { maxSize: 64 * CONFIG_SIZE.KB, ttlMs: 30 * 24 * 60 * 60 * 1000 });
cleanupTtlPrefixKeys('pk_clipboard_magnet_ignore_', { maxSize: 64 * CONFIG_SIZE.KB, ttlMs: 24 * 60 * 60 * 1000 });
cleanupTtlPrefixKeys('pk_clipboard_magnet_last_', { maxSize: 64 * CONFIG_SIZE.KB, ttlMs: 7 * 24 * 60 * 60 * 1000 });
}

let configPrefixCleanupTimer = 0;
function shouldCleanupAfterConfigWrite(key) {
const schema = getConfigLimitSchema(key);
return !!(schema && (schema.isPrefix || schema.ttl || ['pk_ghost_files', 'pk_pwd_vault', 'pk_share_parse_history', 'pk_share_limits', 'pk_expired_shares'].includes(schema.key)));
}

function scheduleConfigPrefixCleanup(reason = 'write', delay = 1200) {
try {
if (configPrefixCleanupTimer) clearTimeout(configPrefixCleanupTimer);
configPrefixCleanupTimer = setTimeout(() => {
configPrefixCleanupTimer = 0;
const run = () => { try { cleanupConfigPrefixKeys(); } catch (e) { console.warn('[ConfigLimit] cleanup failed:', e); } };
if (typeof requestIdleCallback === 'function') requestIdleCallback(run, { timeout: 3000 });
else setTimeout(run, 0);
}, delay);
} catch (e) {}
}

if (window.self !== window.top) return;

const parseCloudLinks = (rawString, isSmartFix) => {
const formattedVal = String(rawString || '').replace(/(https?:\/\/|ftp:\/\/|sftp:\/\/|magnet:\?|ed2k:\/\/|thunder:\/\/)/gi, '\n$1');
const lines = formattedVal.split('\n').map(l => l.trim()).filter(l => l);
const uniqueTasks = new Map();
const linkRegex = /^(https?:\/\/|ftp:\/\/|sftp:\/\/|magnet:\?|ed2k:\/\/|thunder:\/\/)/i;
const base32ToHex = (b32) => {
const alphabet = "ABCDEFGHIJKLMNOPQRSTUVWXYZ234567";
let bits = "";
const input = String(b32 || '').toUpperCase();
for (let i = 0; i < input.length; i++) {
const val = alphabet.indexOf(input[i]);
if (val === -1) return null;
bits += val.toString(2).padStart(5, '0');
}
let hex = "";
for (let i = 0; i + 4 <= bits.length; i += 4) {
const chunk = bits.substring(i, i + 4);
const num = parseInt(chunk, 2);
if (!isNaN(num)) hex += num.toString(16);
}
return hex.toUpperCase();
};
const extractHexHash = (url) => {
const match = String(url || '').match(/urn:btih:([^&]+)/i);
if (!match) return null;
const hash = match[1].toUpperCase();
if (hash.length === 40) return hash;
if (hash.length === 32) return base32ToHex(hash);
return null;
};
const addResult = (url) => {
const hash = extractHexHash(url);
if (hash) {
if (!uniqueTasks.has(hash)) uniqueTasks.set(hash, url);
} else {
uniqueTasks.set(url, url);
}
};
for (let i = 0; i < lines.length; i++) {
let line = lines[i];
if (linkRegex.test(line)) {
addResult(line);
continue;
}
if (isSmartFix) {
let cleanedStr = line.replace(/[^a-zA-Z0-9]/g, '');
const hexMatches = cleanedStr.matchAll(/([a-fA-F0-9]{40})/g);
for (const match of hexMatches) {
addResult(`magnet:?xt=urn:btih:${match[1].toUpperCase()}`);
cleanedStr = cleanedStr.replace(match[1], ' '.repeat(40));
}
const b32Matches = cleanedStr.matchAll(/([a-zA-Z2-7]{32})/g);
for (const match of b32Matches) {
const hex = base32ToHex(match[1].toUpperCase());
if (hex) addResult(`magnet:?xt=urn:btih:${hex}`);
}
}
}
return Array.from(uniqueTasks.values());
};

(() => {
const inject = () => {
const s = document.createElement('script');
s.textContent = `(function(){
const _f = window.fetch;
window.fetch = async function(...args) {
const raw = args[0];
const url = raw && raw.url ? raw.url : (raw ? raw.toString() : '');

if (url.includes('area_accessible')) {
return new Promise((_, reject) => {
    reject(new Error("Bypassed area_accessible"));
});
}

const isTurbo = localStorage.getItem('pk_turbo_mode') === 'true';

if (isTurbo) {
if (location.href.includes('/login') || location.pathname.includes('login')) {
    return _f.apply(this, args);
}

if (url.includes(':incremental_sync') || url.includes(':sync')) {
    return new Response(JSON.stringify({
        error_code: 0,
        data: [],
        files: [],
        tasks: [],
        next_page_token: ''
    }), {status: 200, headers: {'Content-Type': 'application/json'}});
}

try {
    const opts = args[1] || {};
    let cap = null;
    let auth = null;
    if (opts.headers) {
        if (opts.headers instanceof Headers) {
            cap = opts.headers.get('x-captcha-token') || opts.headers.get('X-Captcha-Token');
            auth = opts.headers.get('authorization') || opts.headers.get('Authorization');
        }
        else if (typeof opts.headers === 'object') {
            const capKey = Object.keys(opts.headers).find(k => k.toLowerCase() === 'x-captcha-token');
            if (capKey) cap = opts.headers[capKey];
            const authKey = Object.keys(opts.headers).find(k => k.toLowerCase() === 'authorization');
            if (authKey) auth = opts.headers[authKey];
        }
    }
    if (cap && cap.length > 20) localStorage.setItem('pk_captured_captcha', String(cap).slice(0, 2048));

    if (auth && auth.length > 20) document.dispatchEvent(new CustomEvent('pk-token-captured', { detail: auth }));
} catch (e) {}
}

const res = await _f.apply(this, args);

try {
const u = url.split('?')[0];
const authReadyUrl = u.includes('/drive/v1/about') || u.includes('/v1/user/me');
const authErrorUrl = u.includes('/drive/v1/about') || u.includes('/drive/v1/files') || u.includes('/v1/user/me') || u.includes('/v1/auth/token');
if (res && res.ok && authReadyUrl) {
    document.dispatchEvent(new CustomEvent('pk-official-auth-ready', { detail: { url: u, status: res.status } }));
} else if (res && authErrorUrl && (res.status === 401 || res.status === 403 || res.status === 400)) {
    document.dispatchEvent(new CustomEvent('pk-official-auth-error', { detail: { url: u, status: res.status } }));
}
} catch (e) {}

return res;
};

const _W = window.Worker;
window.Worker = function(url, opts) {
const isTurbo = localStorage.getItem('pk_turbo_mode') === 'true';
if (!isTurbo) return new _W(url, opts);

if (location.href.includes('/login') || location.pathname.includes('login')) {
return new _W(url, opts);
}

const u = url ? url.toString() : '';
const blockList = ['query_db', 'sync', 'database', 'index', 'calc_sha1', 'query_docs'];

if (blockList.some(k => u.includes(k))) {
return new _W('data:application/javascript,self.onmessage=()=>{}');
}
return new _W(url, opts);
};

})()`;
(document.head || document.documentElement).appendChild(s).remove();
};
inject();
})();

window.addEventListener('beforeunload', (e) => {
const activeStatus = ['UPLOADING', 'HASHING', 'WAITING', 'RUNNING', 'PAUSED'];
const tasks = pkState?.uploadTasks || [];
if (tasks.some(t => activeStatus.includes(t.status))) {
e.preventDefault();
return e.returnValue;
}
});

window.pkAddGhostFile = function(id) {
try {
const ghosts = JSON.parse(localStorage.getItem('pk_ghost_files') || '[]');
if (!ghosts.includes(id)) {
ghosts.push(id);
localStorage.setItem('pk_ghost_files', normalizeConfigValue('pk_ghost_files', ghosts, 'localWrite'));
}
} catch(e){}
};
window.pkRemoveGhostFile = function(id) {
try {
const ghosts = JSON.parse(localStorage.getItem('pk_ghost_files') || '[]');
const updated = ghosts.filter(x => x !== id);
localStorage.setItem('pk_ghost_files', normalizeConfigValue('pk_ghost_files', updated, 'localWrite'));
} catch(e){}
};
window.pkCleanupGhostFiles = function() {
try {
const ghosts = JSON.parse(localStorage.getItem('pk_ghost_files') || '[]');
if (ghosts.length > 0) {
const BATCH_SIZE = 100;
for (let i = 0; i < ghosts.length; i += BATCH_SIZE) {
const chunk = ghosts.slice(i, i + BATCH_SIZE);
fetch('https://api-drive.mypikpak.com/drive/v1/files:batchDelete', {
method: 'POST',
headers: getHeaders(),
body: JSON.stringify({ ids: chunk })
}).catch(()=>{});
}
localStorage.setItem('pk_ghost_files', normalizeConfigValue('pk_ghost_files', [], 'localWrite'));
}
} catch(e){}

try {
const phases = "PHASE_TYPE_UNKNOW,PHASE_TYPE_PENDING,PHASE_TYPE_RUNNING,PHASE_TYPE_PAUSED,PHASE_TYPE_ERROR";
const filters = encodeURIComponent(JSON.stringify({ "phase": { "in": phases } }));
const url = `https://api-drive.mypikpak.com/drive/v1/tasks?type=upload&limit=100&filters=${filters}&_t=${Date.now()}`;
fetch(url, { headers: getHeaders() })
.then(res => res.json())
.then(cloudData => {
const cloudTasks = cloudData.tasks || [];
const ghostIds = [];
cloudTasks.forEach(ct => {
if (ct.file_id) {
const ref = ct.reference_resource || {};
const taskName = ref.name || ct.name || ct.file_name || 'Ghost Task';
if (taskName === 'upload' || taskName === 'Ghost Task') {
    ghostIds.push(ct.file_id);
}
}
});
if (ghostIds.length > 0) {
fetch('https://api-drive.mypikpak.com/drive/v1/files:batchDelete', {
method: 'POST', headers: getHeaders(), body: JSON.stringify({ ids: ghostIds })
}).catch(()=>{});
}
}).catch(()=>{});
} catch (e) {}
};

window.addEventListener('beforeunload', () => {
const tasks = pkState?.uploadTasks || [];
const filesToDelete = tasks.filter(t => t.status !== 'DONE' && t.file_id && !t._deleted).map(t => t.file_id);
if (filesToDelete.length > 0) {
const BATCH_SIZE = 100;
for (let i = 0; i < filesToDelete.length; i += BATCH_SIZE) {
const chunk = filesToDelete.slice(i, i + BATCH_SIZE);
try {
fetch('https://api-drive.mypikpak.com/drive/v1/files:batchDelete', {
method: 'POST',
headers: getHeaders(),
body: JSON.stringify({ ids: chunk }),
keepalive: true
}).catch(()=>{});
} catch(e) {}
}
if (typeof window.pkRemoveGhostFile === 'function') {
filesToDelete.forEach(id => window.pkRemoveGhostFile(id));
}
}
});

;
