function getDefaultPotPlayerProtocolState() {
return {
schemaVersion: CONF.potplayerProtocolStateSchemaVersion,
repairVersion: "",
confirmedRepairVersion: "",
installRegDownloadedAt: 0,
deleteRegDownloadedAt: 0,
customPlayerPath: "",
customPlayerPathUpdatedAt: 0,
pathBoundRepairVersion: "",
userConfirmedFixedAt: 0,
lastPromptAt: 0,
neverAutoPrompt: false,
suppressUntil: 0
};
}

function normalizePotPlayerProtocolState(rawState) {
const def = getDefaultPotPlayerProtocolState();
let data = rawState;
if (typeof data === 'string') {
try { data = data ? JSON.parse(data) : null; } catch (e) { data = null; }
}
if (!data || typeof data !== 'object' || Array.isArray(data)) return def;

const toTime = (v) => {
const n = Number(v);
return Number.isFinite(n) && n > 0 ? n : 0;
};

return {
schemaVersion: CONF.potplayerProtocolStateSchemaVersion,
repairVersion: typeof data.repairVersion === 'string' ? data.repairVersion : "",
confirmedRepairVersion: typeof data.confirmedRepairVersion === 'string' ? data.confirmedRepairVersion : "",
installRegDownloadedAt: toTime(data.installRegDownloadedAt),
deleteRegDownloadedAt: toTime(data.deleteRegDownloadedAt),
customPlayerPath: typeof data.customPlayerPath === 'string' ? data.customPlayerPath : "",
customPlayerPathUpdatedAt: toTime(data.customPlayerPathUpdatedAt),
pathBoundRepairVersion: typeof data.pathBoundRepairVersion === 'string' ? data.pathBoundRepairVersion : "",
userConfirmedFixedAt: toTime(data.userConfirmedFixedAt),
lastPromptAt: toTime(data.lastPromptAt),
neverAutoPrompt: data.neverAutoPrompt === true,
suppressUntil: toTime(data.suppressUntil)
};
}

function readPotPlayerProtocolState() {
try {
const state = normalizePotPlayerProtocolState(gmGet(CONF.potplayerProtocolStateKey, ''));
const storedPath = gmGet(CONF.potplayerCustomPathKey, '');
const checkedStoredPath = validatePotPlayerCustomPath(storedPath);
if (checkedStoredPath.ok) {
state.customPlayerPath = checkedStoredPath.path;
return state;
}
const checkedLegacyPath = validatePotPlayerCustomPath(state.customPlayerPath);
if (checkedLegacyPath.ok && !storedPath) {
gmSet(CONF.potplayerCustomPathKey, checkedLegacyPath.path);
state.customPlayerPath = checkedLegacyPath.path;
}
return state;
} catch (e) {
return getDefaultPotPlayerProtocolState();
}
}

function writePotPlayerProtocolState(state) {
try {
const normalized = normalizePotPlayerProtocolState(state);
const rawPath = String(normalized.customPlayerPath || '').trim();

if (!rawPath) {
normalized.customPlayerPath = '';
gmSet(CONF.potplayerProtocolStateKey, normalized);
if (typeof GM_deleteValue !== 'undefined') GM_deleteValue(CONF.potplayerCustomPathKey);
try { localStorage.removeItem(CONF.potplayerCustomPathKey); } catch (e) {}
return;
}

const checkedPath = validatePotPlayerCustomPath(rawPath);
if (checkedPath.ok) {
normalized.customPlayerPath = checkedPath.path;
gmSet(CONF.potplayerCustomPathKey, checkedPath.path);
} else {
const storedPath = gmGet(CONF.potplayerCustomPathKey, '');
const checkedStoredPath = validatePotPlayerCustomPath(storedPath);
normalized.customPlayerPath = checkedStoredPath.ok ? checkedStoredPath.path : '';
}

gmSet(CONF.potplayerProtocolStateKey, normalized);
} catch (e) {}
}

function updatePotPlayerProtocolState(patch = {}) {
const state = readPotPlayerProtocolState();
Object.assign(state, patch, { repairVersion: CONF.potplayerProtocolRepairVersion });
writePotPlayerProtocolState(state);
return state;
}

function recordPotPlayerProtocolRegDownload(kind) {
const now = Date.now();
const patch = kind === 'delete' ? { deleteRegDownloadedAt: now } : { installRegDownloadedAt: now };
return updatePotPlayerProtocolState(patch);
}

function recordPotPlayerProtocolUserFixed() {
const now = Date.now();
const state = readPotPlayerProtocolState();
const patch = {
confirmedRepairVersion: CONF.potplayerProtocolRepairVersion,
userConfirmedFixedAt: now
};
if (state.customPlayerPath) {
patch.pathBoundRepairVersion = CONF.potplayerProtocolRepairVersion;
}
return updatePotPlayerProtocolState(patch);
}

function recordPotPlayerProtocolAutoPrompt() {
return updatePotPlayerProtocolState({ lastPromptAt: Date.now() });
}

function suppressPotPlayerAutoPromptToday() {
return updatePotPlayerProtocolState({ suppressUntil: Date.now() + CONF.potplayerSuppressTodayTTL });
}

function disablePotPlayerAutoPrompt() {
return updatePotPlayerProtocolState({ neverAutoPrompt: true });
}

function shouldAutoPromptPotPlayerRepair(playUrl) {
const cleanUrl = String(playUrl || '').trim();
if (!cleanUrl) return false;

const now = Date.now();
const launchState = readPotPlayerLaunchState();
const protocolState = readPotPlayerProtocolState();

if (launchState.consecutiveFailCount < CONF.potplayerAutoRepairFailThreshold) return false;
if (launchState.lastLikelyOpenAt > 0 && now - launchState.lastLikelyOpenAt < CONF.potplayerLikelyOpenTrustTTL) return false;
if (protocolState.suppressUntil > now) return false;
if (protocolState.neverAutoPrompt === true) return false;
if (protocolState.lastPromptAt > 0 && now - protocolState.lastPromptAt < CONF.potplayerPromptCooldown) return false;

return true;
}

function schedulePotPlayerAutoRepairPrompt(playUrl, opts = {}) {
const cleanUrl = String(playUrl || '').trim();
if (!cleanUrl) return;
if (opts.autoRepairPrompt === false) return;

const source = normalizePotPlayerLaunchSource(opts.source);
const autoPromptDelay = Number.isFinite(Number(opts.autoRepairPromptDelay)) ? Math.max(0, Number(opts.autoRepairPromptDelay)) : 180;

setTimeout(() => {
if (!shouldAutoPromptPotPlayerRepair(cleanUrl)) return;
recordPotPlayerProtocolAutoPrompt();
openPotPlayerProtocolRepairHelper(cleanUrl, {
source,
autoPrompt: true,
button: null
});
}, autoPromptDelay);
}

function clearPotPlayerLaunchFailCount() {
const state = readPotPlayerLaunchState();
state.consecutiveFailCount = 0;
writePotPlayerLaunchState(state);
return state;
}

function escapeRegString(value) {
return String(value || '').replace(/\\/g, '\\\\').replace(/"/g, '\\"');
}

function normalizePotPlayerCustomPath(input) {
return String(input || '').trim().replace(/^["']+|["']+$/g, '').trim();
}

function validatePotPlayerCustomPath(input) {
const path = normalizePotPlayerCustomPath(input);
if (!path) return { ok: false, path };
if (!/\.exe$/i.test(path)) return { ok: false, path };
if (!(/[A-Za-z]:\\/.test(path) || path.includes('\\'))) return { ok: false, path };
if (/[\r\n]/.test(path)) return { ok: false, path };
return { ok: true, path };
}

function savePotPlayerCustomPath(input) {
const checked = validatePotPlayerCustomPath(input);
if (!checked.ok) return { ok: false, changed: false, path: checked.path };

const state = readPotPlayerProtocolState();
const oldPath = state.customPlayerPath || "";
const changed = oldPath !== checked.path;
const patch = { customPlayerPath: checked.path };
if (changed) {
patch.customPlayerPathUpdatedAt = Date.now();
patch.confirmedRepairVersion = "";
patch.pathBoundRepairVersion = "";
}
updatePotPlayerProtocolState(patch);
return { ok: true, changed, wasConfigured: !!oldPath, path: checked.path };
}

function getValidSavedPotPlayerPath() {
const state = readPotPlayerProtocolState();
const checked = validatePotPlayerCustomPath(state.customPlayerPath);
return checked.ok ? checked.path : "";
}

function buildPotPlayerInstallReg(customPlayerPath = "") {
const checked = validatePotPlayerCustomPath(customPlayerPath);
const hasCustomPath = checked.ok;
const command = hasCustomPath
? `"${checked.path}" "%1"`
: 'cmd.exe /d /s /c "start "" "PotPlayerMini64.exe" "%1" || start "" "PotPlayerMini.exe" "%1" || start "" "PotPlayer.exe" "%1""';
const defaultIcon = hasCustomPath ? `"${checked.path}",1` : 'PotPlayerMini64.exe,1';
return [
'Windows Registry Editor Version 5.00',
'',
'; PikPak Enhancement Master - PotPlayer protocol repair',
'; User-level protocol registration only. No browser policy is written.',
hasCustomPath ? '; This file binds potplayer:// to the custom PotPlayer executable path below.' : '; This file uses the PotPlayer executable discoverable from the Windows path.',
'',
'[HKEY_CURRENT_USER\\Software\\Classes\\potplayer]',
'@="URL:PotPlayer Protocol"',
'"URL Protocol"=""',
'',
'[HKEY_CURRENT_USER\\Software\\Classes\\potplayer\\DefaultIcon]',
`@="${escapeRegString(defaultIcon)}"`,
'',
'[HKEY_CURRENT_USER\\Software\\Classes\\potplayer\\shell]',
'@="open"',
'',
'[HKEY_CURRENT_USER\\Software\\Classes\\potplayer\\shell\\open]',
'@="open"',
'',
'[HKEY_CURRENT_USER\\Software\\Classes\\potplayer\\shell\\open\\command]',
`@="${escapeRegString(command)}"`,
''
].join('\r\n');
}

function buildPotPlayerDeleteReg() {
return [
'Windows Registry Editor Version 5.00',
'',
'; PikPak Enhancement Master - PotPlayer protocol cleanup',
'; User-level cleanup only. System-level registrations are not modified.',
'',
'[-HKEY_CURRENT_USER\\Software\\Classes\\potplayer]',
''
].join('\r\n');
}

function makeUtf16LeBlob(text) {
const input = String(text || '');
const buffer = new ArrayBuffer(2 + input.length * 2);
const view = new DataView(buffer);
view.setUint16(0, 0xFEFF, true);
for (let i = 0; i < input.length; i++) {
view.setUint16(2 + i * 2, input.charCodeAt(i), true);
}
return new Blob([buffer], { type: 'application/octet-stream' });
}

function downloadPotPlayerRegFile(kind) {
const isDelete = kind === 'delete';
const savedPath = getValidSavedPotPlayerPath();
if (!isDelete && !savedPath) return false;
const content = isDelete ? buildPotPlayerDeleteReg() : buildPotPlayerInstallReg(savedPath);
const blob = makeUtf16LeBlob(content);
const url = URL.createObjectURL(blob);
const a = document.createElement('a');
a.href = url;
a.download = isDelete ? CONF.potplayerRegDeleteFileName : CONF.potplayerRegCustomInstallFileName;
a.click();
setTimeout(() => URL.revokeObjectURL(url), 1000);
recordPotPlayerProtocolRegDownload(isDelete ? 'delete' : 'install');
return true;
}

function getDefaultPotPlayerLaunchState() {
return {
schemaVersion: CONF.potplayerLaunchStateSchemaVersion,
lastLikelyOpenAt: 0,
lastLikelyFailAt: 0,
consecutiveFailCount: 0,
lastFailSource: "",
lastCopiedAt: 0,
lastLaunchAt: 0
};
}

function normalizePotPlayerLaunchState(rawState) {
const def = getDefaultPotPlayerLaunchState();
let data = rawState;
if (typeof data === 'string') {
try { data = data ? JSON.parse(data) : null; } catch (e) { data = null; }
}
if (!data || typeof data !== 'object' || Array.isArray(data)) return def;

const toTime = (v) => {
const n = Number(v);
return Number.isFinite(n) && n > 0 ? n : 0;
};
const toCount = (v) => {
const n = parseInt(v, 10);
return Number.isFinite(n) && n > 0 ? n : 0;
};

return {
schemaVersion: CONF.potplayerLaunchStateSchemaVersion,
lastLikelyOpenAt: toTime(data.lastLikelyOpenAt),
lastLikelyFailAt: toTime(data.lastLikelyFailAt),
consecutiveFailCount: toCount(data.consecutiveFailCount),
lastFailSource: typeof data.lastFailSource === 'string' ? data.lastFailSource : "",
lastCopiedAt: toTime(data.lastCopiedAt),
lastLaunchAt: toTime(data.lastLaunchAt)
};
}

function readPotPlayerLaunchState() {
try {
return normalizePotPlayerLaunchState(gmGet(CONF.potplayerLaunchStateKey, ''));
} catch (e) {
return getDefaultPotPlayerLaunchState();
}
}

function writePotPlayerLaunchState(state) {
try {
gmSet(CONF.potplayerLaunchStateKey, normalizePotPlayerLaunchState(state));
} catch (e) {}
}

function normalizePotPlayerLaunchSource(source) {
return ['normal', 'error_fallback', 'unknown'].includes(source) ? source : 'unknown';
}

function recordPotPlayerLaunchAttempt(source, launchAt = Date.now()) {
const state = readPotPlayerLaunchState();
const time = Number.isFinite(Number(launchAt)) && Number(launchAt) > 0 ? Number(launchAt) : Date.now();
state.lastLaunchAt = time;
writePotPlayerLaunchState(state);
return state;
}

function recordPotPlayerLaunchResult(result, opts = {}) {
const now = Date.now();
const launchAt = Number.isFinite(Number(opts.launchAt)) && Number(opts.launchAt) > 0 ? Number(opts.launchAt) : now;
const copiedAt = Number.isFinite(Number(opts.copiedAt)) && Number(opts.copiedAt) > 0 ? Number(opts.copiedAt) : now;
const source = normalizePotPlayerLaunchSource(opts.source);
const state = readPotPlayerLaunchState();

if (result === 'likely_open') {
state.lastLikelyOpenAt = now;
state.lastLaunchAt = launchAt;
state.consecutiveFailCount = 0;
state.lastFailSource = "";
} else if (result === 'likely_fail') {
state.lastLikelyFailAt = now;
state.lastLaunchAt = launchAt;
state.lastCopiedAt = copiedAt;
state.consecutiveFailCount += 1;
state.lastFailSource = source;
} else {
return state;
}

writePotPlayerLaunchState(state);
return state;
}

function getBlurScope() {
const legacyBlur = gmGet('pk_blur_thumb', false);
const scope = gmGet('pk_blur_scope', legacyBlur ? 'list' : 'off');
return ['off', 'list', 'grid', 'both'].includes(scope) ? scope : (legacyBlur ? 'list' : 'off');
}
function isBlurEnabledForView(view) {
const scope = getBlurScope();
return scope === 'both' || scope === view;
}

const calcSha1 = async (file) => {
if (!window.crypto || !window.crypto.subtle) return "";
const hexFromBytes = (bytes) => Array.from(bytes).map(b => b.toString(16).padStart(2, '0')).join('').toUpperCase();
const sha1Bytes = async (buffer) => new Uint8Array(await crypto.subtle.digest('SHA-1', buffer));
const calcXunleiCid = async () => {
const CID_SAMPLE_SIZE = 0x5000;
if (file.size < 0xF000) return hexFromBytes(await sha1Bytes(await file.arrayBuffer()));
const head = file.slice(0, CID_SAMPLE_SIZE);
const midStart = Math.floor(file.size / 3);
const mid = file.slice(midStart, midStart + CID_SAMPLE_SIZE);
const tail = file.slice(Math.max(0, file.size - CID_SAMPLE_SIZE), file.size);
return hexFromBytes(await sha1Bytes(await new Blob([head, mid, tail]).arrayBuffer()));
};
const calcXunleiGcid = async () => {
let partSize = 0x40000;
while ((file.size / partSize) > 0x200 && partSize < 0x200000) partSize <<= 1;
const digests = [];
if (file.size === 0) digests.push(await sha1Bytes(new ArrayBuffer(0)));
for (let offset = 0; offset < file.size; offset += partSize) {
const buffer = await file.slice(offset, Math.min(file.size, offset + partSize)).arrayBuffer();
digests.push(await sha1Bytes(buffer));
}
const merged = new Uint8Array(digests.length * 20);
digests.forEach((bytes, index) => merged.set(bytes, index * 20));
return hexFromBytes(await sha1Bytes(merged.buffer));
};
const queryGcidByCid = async (cid) => {
try {
const res = await fetch(`https://api-drive.mypikpak.com/drive/v1/resource/cid?cid=${encodeURIComponent(String(cid || '').toLowerCase())}&file_size=${encodeURIComponent(String(file.size || 0))}`, { method: 'GET', headers: getHeaders() });
if (!res.ok) return "";
const data = await res.json().catch(() => null);
return data && data.gcid ? String(data.gcid).toUpperCase() : "";
} catch (e) {
console.warn('[Upload] CID precheck failed:', e);
return "";
}
};
const cid = await calcXunleiCid();
const gcid = await queryGcidByCid(cid);
return gcid || await calcXunleiGcid();
};

function getLang(){const u=gmGet('pk_lang','');if(u)return u;const n=navigator.language.toLowerCase();return (n==='zh'||n.startsWith('zh-cn')||n.startsWith('zh-sg'))?'zh':(n.startsWith('zh-tw')||n.startsWith('zh-hk')||n.startsWith('zh-mo'))?'tc':(n.startsWith('id')||n.startsWith('in'))?'id':n.startsWith('ms')?'ms':n.startsWith('ko')?'ko':n.startsWith('ja')?'ja':'en';}
const I18N_CONF={defaultLang:'zh',remoteLangs:['tc','en','ko','ja','id','ms'],manifestUrl:'https://cdn.jsdelivr.net/gh/digbug82/PikPak_Enhancement_Master@main/i18n/manifest.json',baseUrl:'https://cdn.jsdelivr.net/gh/digbug82/PikPak_Enhancement_Master@main/i18n/',cachePrefix:'pk_i18n_',manifestKey:'pk_i18n_manifest',cacheTTL:7*24*60*60*1000,manifestTTL:24*60*60*1000,requiredKeys:['title','modal_settings_title','label_lang','msg_settings_saved','btn_nav_home']};
let pkRemoteI18n=null;
let pkI18nReadyPromise=null;
let pkI18nReadyLang='';
function getI18nCacheKey(lang){return `${I18N_CONF.cachePrefix}${lang}`;}
function readI18nCache(lang,expectedVersion=''){try{const raw=gmGet(getI18nCacheKey(lang),'');if(!raw)return null;const parsed=typeof raw==='string'?JSON.parse(raw):raw;if(!parsed||parsed.lang!==lang||!parsed.data||typeof parsed.data!=='object'||Array.isArray(parsed.data))return null;if(parsed.expiresAt&&parsed.expiresAt<Date.now())return null;if(expectedVersion&&String(parsed.version||'')!==String(expectedVersion))return null;return parsed;}catch(e){return null;}}
function writeI18nCache(lang,version,data){try{gmSet(getI18nCacheKey(lang),JSON.stringify({lang,version:String(version||''),data,expiresAt:Date.now()+I18N_CONF.cacheTTL}));}catch(e){}}
function readI18nManifestCache(){try{const raw=gmGet(I18N_CONF.manifestKey,'');if(!raw)return null;const parsed=typeof raw==='string'?JSON.parse(raw):raw;if(!parsed||!parsed.data||typeof parsed.data!=='object')return null;if(parsed.expiresAt&&parsed.expiresAt<Date.now())return null;return parsed.data;}catch(e){return null;}}
function writeI18nManifestCache(data){try{gmSet(I18N_CONF.manifestKey,JSON.stringify({data,expiresAt:Date.now()+I18N_CONF.manifestTTL}));}catch(e){}}
async function fetchI18nJson(url){const res=await fetch(url,{cache:'no-store'});if(!res.ok)throw new Error(`HTTP ${res.status}`);return await res.json();}
function mergeI18nPack(base,extra){return Object.assign({},base||{},extra&&typeof extra==='object'&&!Array.isArray(extra)?extra:{});}
function isValidI18nManifest(manifest){return !!(manifest&&typeof manifest==='object'&&!Array.isArray(manifest)&&manifest.files&&typeof manifest.files==='object'&&String(manifest.version||'').trim());}
function isValidI18nPayload(data){return !!(data&&typeof data==='object'&&!Array.isArray(data)&&I18N_CONF.requiredKeys.every(k=>Object.prototype.hasOwnProperty.call(data,k)));}
async function loadI18nManifest(force=false){if(!force){const cached=readI18nManifestCache();if(isValidI18nManifest(cached))return cached;}const manifestUrl=`${I18N_CONF.manifestUrl}${I18N_CONF.manifestUrl.includes('?')?'&':'?'}_t=${Date.now()}`;const manifest=await fetchI18nJson(manifestUrl);if(!isValidI18nManifest(manifest))throw new Error('Invalid i18n manifest');writeI18nManifestCache(manifest);return manifest;}
async function loadRemoteLangPack(force=false,langOverride=''){const lang=langOverride||getLang();if(!I18N_CONF.remoteLangs.includes(lang)||!I18N_CONF.manifestUrl){pkRemoteI18n=null;return null;}const manifest=await loadI18nManifest(force);const version=String(manifest.version||'');if(!force){const cached=readI18nCache(lang,version);if(cached){pkRemoteI18n={lang,version:cached.version,data:cached.data};return pkRemoteI18n;}}const file=manifest.files&&manifest.files[lang];if(!file){pkRemoteI18n=null;return null;}const baseUrl=manifest.baseUrl||I18N_CONF.baseUrl;const fileUrl=/^https?:\/\//.test(file)?file:`${baseUrl}${file}`;const data=await fetchI18nJson(`${fileUrl}${fileUrl.includes('?')?'&':'?'}_v=${encodeURIComponent(version)}`);if(!isValidI18nPayload(data))throw new Error('Invalid i18n payload');writeI18nCache(lang,version,data);pkRemoteI18n={lang,version,data};return pkRemoteI18n;}
function ensureI18nReady(force=false,langOverride=''){const lang=langOverride||getLang();if(force||!pkI18nReadyPromise||pkI18nReadyLang!==lang){pkI18nReadyLang=lang;pkI18nReadyPromise=loadRemoteLangPack(force,lang).catch(()=>null);}return pkI18nReadyPromise;}
async function ensureI18nReadyBeforeOpen(langOverride=''){const lang=langOverride||getLang();if(lang==='zh')return null;try{return await Promise.race([ensureI18nReady(false,lang),sleep(4000).then(()=>null)]);}catch(e){return null;}}
