return `<span class="pk-gv-folder-base" style="display:${display};align-items:center;justify-content:center;width:100%;height:100%;opacity:${opacity};transition:opacity .18s ease;position:relative;"><span class="pk-gv-folder-fallback" style="display:inline-flex;align-items:center;justify-content:center;opacity:${showFallbackFirst ? '1' : '0'};transition:opacity .12s ease;">${svgHtml}</span>${remoteHtml}</span>`;
