function showPrompt(msg, val = '', title = L.title_prompt, opt = {}) {
return new Promise((resolve) => {
const cleanTitle = esc(msg).replace(/[:：]$/, '');
const isNewFolder = (title === L.btn_newfolder);
const okBtnText = isNewFolder ? L.btn_create : L.btn_ok;
const duplicateText = opt.duplicateText || L.err_name_exists;
const duplicateCheck = typeof opt.duplicateCheck === 'function'
? opt.duplicateCheck
: (v) => S.items.some(item => item.name === v && item.name !== val);

const m = showModal(`
<h3 style="border:none; margin-bottom:24px; font-size:18px; font-weight:700; color:var(--pk-fg);">${cleanTitle}</h3>
<div style="position:relative;">
<input type="text" id="prm_input" value="${esc(val)}"
    style="width:100%; height:44px; padding:0 12px; border:2px solid var(--pk-bd); border-radius:8px; background:var(--pk-bg); color:var(--pk-fg); font-size:15px; font-weight:600; outline:none; transition:border-color 0.2s; box-sizing:border-box;">
<div style="position:absolute; top:0; transform:translateY(-50%); left:10px; background:var(--pk-bg); padding:0 5px; font-size:11px; color:var(--pk-pri); font-weight:bold; line-height:1;">${title}</div>
<div id="prm_err" class="pk-input-err-msg" style="color:#ff4d4f; font-size:12px; margin-top:8px; min-height:18px; visibility:hidden; font-weight:500;">${esc(duplicateText)}</div>
</div>
<div class="pk-modal-act" style="margin-top:15px; display:flex; justify-content:flex-end; gap:12px;">
<button class="pk-btn" id="prm_cancel" style="height:40px; min-width:86px; padding:0 24px; border-radius:8px; justify-content:center; background:transparent;">${L.btn_cancel}</button>
<button class="pk-btn pri" id="prm_ok" style="height:40px; min-width:86px; padding:0 24px; border-radius:8px; background:var(--pk-pri); color:#fff; font-weight:bold; justify-content:center;">${okBtnText}</button>
</div>
`);

const modalBox = m.querySelector('.pk-modal');
if (modalBox) {
Object.assign(modalBox.style, { width: '480px', height: 'auto', minHeight: 'auto', padding: '30px' });
const closeBtn = m.querySelector('.pk-modal-close');
if (closeBtn) Object.assign(closeBtn.style, { top: '26px', right: '26px' });
}

const inp = m.querySelector('#prm_input');
const err = m.querySelector('#prm_err');
const okBtn = m.querySelector('#prm_ok');

const maxLen = Math.max(0, Number(opt.maxLen || 0));
let lastLimitTipAt = 0;
const showLimitTip = () => {
const now = Date.now();
if (now - lastLimitTipAt < 1500) return;
lastLimitTipAt = now;
showPikPakFileNameLimitTip();
};
const validate = (notify = false) => {
const v = inp.value.trim();
const isEmpty = v === '';
const isTooLong = !!(maxLen && v.length > maxLen);
const isDup = !isTooLong && !!v && duplicateCheck(v);

err.textContent = isTooLong ? getStrings().msg_config_input_over_limit : duplicateText;
err.style.visibility = (isTooLong || isDup) ? 'visible' : 'hidden';

if (isTooLong && notify) showLimitTip();

if (isDup || isEmpty || isTooLong) {
okBtn.disabled = true;
okBtn.style.opacity = '0.4';
okBtn.style.cursor = 'not-allowed';
inp.style.borderColor = (isDup || isTooLong) ? '#ff4d4f' : 'var(--pk-bd)';
}
else if (v === val) {
okBtn.disabled = false;
okBtn.style.opacity = '1';
okBtn.style.cursor = 'pointer';
inp.style.borderColor = 'var(--pk-bd)';
}
else {
okBtn.disabled = false;
okBtn.style.opacity = '1';
okBtn.style.cursor = 'pointer';
inp.style.borderColor = 'var(--pk-pri)';
}
};

inp.focus();
if (val && val.includes('.') && val.lastIndexOf('.') > 0) {
inp.setSelectionRange(0, val.lastIndexOf('.'));
} else {
inp.select();
}

inp.addEventListener('input', () => validate(true));
validate(false);

inp.onkeydown = (e) => {
if (e.key === 'Enter' && !okBtn.disabled) okBtn.click();
if (e.key === 'Escape') {
e.stopPropagation();
m.remove();
resolve(null);
}
};

m.querySelector('#prm_cancel').onclick = () => { m.remove(); resolve(null); };
m.querySelector('#prm_ok').onclick = () => {
const v = inp.value.trim();
if (maxLen && v.length > maxLen) { validate(true); return; }
m.remove();
resolve(v);
};
m.querySelector('.pk-modal-close').onclick = () => { m.remove(); resolve(null); };
});
}

function getPkToastHost() {
return document.fullscreenElement || document.webkitFullscreenElement || document.body;
}

function getPkTopModalZIndex() {
let top = 0;
document.querySelectorAll('.pk-modal-ov').forEach(el => {
const z = Number(getComputedStyle(el).zIndex);
if (Number.isFinite(z)) top = Math.max(top, z);
});
return top;
}

function ensurePkToastContainer() {
let container = document.getElementById('pk-toast-container');
const host = getPkToastHost();
if (!container) {
container = document.createElement('div');
container.id = 'pk-toast-container';
}
const topModalZ = getPkTopModalZIndex();
container.style.zIndex = String(topModalZ >= 2147483647 ? 2147483647 : Math.max(2147483647, topModalZ + 1));
if (host) host.appendChild(container);
return container;
}

function normalizePkToastKeyText(value) {
const div = document.createElement('div');
div.innerHTML = String(value || '');
return (div.textContent || div.innerText || String(value || '')).replace(/\s+/g, ' ').trim();
}

function hidePkToastElement(t) {
if (!t) return;
if (t._pkToastHideTimer) clearTimeout(t._pkToastHideTimer);
if (t._pkToastRemoveTimer) clearTimeout(t._pkToastRemoveTimer);
t.classList.remove('pk-show');
t.classList.add('pk-hide');
t._pkToastRemoveTimer = setTimeout(() => {
if (t.parentNode) t.remove();
}, 300);
}

function schedulePkToastHide(t, displayTime) {
if (!t) return;
if (t._pkToastHideTimer) clearTimeout(t._pkToastHideTimer);
if (t._pkToastRemoveTimer) clearTimeout(t._pkToastRemoveTimer);
t._pkToastHideTimer = setTimeout(() => hidePkToastElement(t), displayTime);
}

function showToast(msg, type = 'success', duration = 0) {
let container = ensurePkToastContainer();
const toastType = String(type || 'success');
const toastText = normalizePkToastKeyText(msg);
const toastKey = `${toastType}|${toastText}`;
const displayTime = duration > 0 ? duration : (toastType === 'success' ? 2200 : 3500);

const ov = document.querySelector('.pk-ov');
const savedThemeNow = gmGet('pk_theme', 'auto');
const sysDarkNow = window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches;
const isDark = ov ? ov.classList.contains('pk-dark') : (savedThemeNow === 'dark' || (savedThemeNow === 'auto' && sysDarkNow));
document.querySelectorAll('.pk-msg-toast').forEach(n => n.classList.toggle('pk-dark', isDark));

const existed = Array.from(document.querySelectorAll('.pk-msg-toast')).find(n => n.dataset.pkToastKey === toastKey && n.parentNode && !n.classList.contains('pk-hide'));
if (existed) {
if (isDark) existed.classList.add('pk-dark');
else existed.classList.remove('pk-dark');
existed.classList.remove('pk-hide');
existed.classList.add('pk-show');
schedulePkToastHide(existed, displayTime);
return;
}

const t = document.createElement('div');
t.className = `pk-msg-toast ${toastType} pk-hide`;
t.dataset.pkToastKey = toastKey;
if (isDark) t.classList.add('pk-dark');

if (toastType === 'error' || toastType === 'warning') {
const icon = pkIconHtml('warning', { style: 'flex-shrink: 0;' });
t.innerHTML = `${icon}<span style="flex: 1; line-height: 1.4;">${esc(msg)}</span>`;
t.style.backgroundColor = toastType === 'warning' ? 'rgba(250, 173, 20, 0.95)' : 'rgba(217, 48, 37, 0.95)';
t.style.color = '#ffffff';
if (toastType === 'warning') t.style.border = '1px solid rgba(250, 173, 20, 0.2)';
} else {
t.textContent = msg;
}

container.prepend(t);
requestAnimationFrame(() => {
t.classList.remove('pk-hide');
t.classList.add('pk-show');
});

schedulePkToastHide(t, displayTime);
}

function showScriptUpdateToast(info) {
const latest = info && info.latestVersion ? String(info.latestVersion) : '';
if (!latest || document.getElementById('pk-script-update-toast') || isScriptUpdateDismissed(latest)) return;

let container = ensurePkToastContainer();

const t = document.createElement('div');
t.id = 'pk-script-update-toast';
t.className = 'pk-script-update-toast';
const ov = document.querySelector('.pk-ov');
const savedThemeNow = gmGet('pk_theme', 'auto');
const sysDarkNow = window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches;
const isDark = ov ? ov.classList.contains('pk-dark') : (savedThemeNow === 'dark' || (savedThemeNow === 'auto' && sysDarkNow));
if (isDark) t.classList.add('pk-dark');

const msg = esc(L.msg_script_update_new).replace('{v}', `<b>${esc(latest)}</b>`);
t.innerHTML = `<span class="pk-script-update-msg">${msg}</span><button type="button" class="pk-script-update-open" data-pk-script-update-open="1">${esc(L.msg_script_update_open)}</button><button type="button" class="pk-script-update-close" data-pk-script-update-close="1">×</button>`;

const openUrl = () => {
const m = {tc:'README(tc).md',en:'README(en).md',ko:'README(ko).md',ja:'README(ja).md',id:'README(id).md',ms:'README(ms).md'};
const f = m[getLang()];
window.open(`${CONF.scriptUpdateProjectUrl}/blob/main/${f ? `i18n/${f}` : 'README.md'}`, '_blank', 'noopener,noreferrer');
};

t.onclick = (e) => {
if (e.target && e.target.closest('[data-pk-script-update-close]')) return;
openUrl();
};

const openBtn = t.querySelector('[data-pk-script-update-open]');
if (openBtn) openBtn.onclick = (e) => { e.preventDefault(); e.stopPropagation(); openUrl(); };

const closeBtn = t.querySelector('[data-pk-script-update-close]');
if (closeBtn) closeBtn.onclick = (e) => {
e.preventDefault();
e.stopPropagation();
markScriptUpdateDismissed(latest);
t.style.opacity = '0';
t.style.transform = 'translateY(-15px) scale(0.95)';
setTimeout(() => { if (t.parentNode) t.remove(); }, 300);
};

container.prepend(t);
requestAnimationFrame(() => {
t.style.transform = 'translateY(0) scale(1)';
t.style.opacity = '1';
});
}

async function runScriptUpdateCheck() {
try {
const info = await fetchScriptUpdateInfo(false);
if (isScriptUpdateNew(info)) showScriptUpdateToast(info);
} catch (e) {}
}

const getBlacklistLineItems = value => String(value || '').split(/\r?\n/).map(x => x.trim()).filter(Boolean);

function getBlacklistAppendStats(storageKey, oldValue, appendValue) {
const schema = getConfigLimitSchema(storageKey);
const limits = (schema && schema.localLimit) || {};
const maxItemLen = limits.maxItemLen || 512;
const oldNorm = normalizeConfigValue(storageKey, oldValue || '', 'localWrite');
const mergedRaw = oldNorm + (oldNorm && !oldNorm.endsWith('\n') ? '\n' : '') + String(appendValue || '');
const normalized = normalizeConfigValue(storageKey, mergedRaw, 'localWrite');
const oldSet = new Set(getBlacklistLineItems(oldNorm));
const newSet = new Set(getBlacklistLineItems(normalized));
let actualAdded = 0;
newSet.forEach(item => { if (!oldSet.has(item)) actualAdded++; });
const seen = new Set(oldSet);
let expectedAdded = 0;
getBlacklistLineItems(appendValue).forEach(line => {
const item = safeStringLimit(line, maxItemLen);
if (!item || seen.has(item)) return;
seen.add(item);
expectedAdded++;
});
return { normalized, actualAdded, expectedAdded, clipped: actualAdded < expectedAdded };
}

