function isShareDetailFolder(raw) {
raw = raw || {};
const mime = raw.mime_type || raw.mimeType || raw.content_type || '';
const kind = String(raw.kind || '').toLowerCase();
return raw.kind === 'drive#folder' || kind === 'folder' || kind.includes('folder') || mime === 'application/x-directory';
}

function getShareDetailFileId(raw, parentId = '', index = 0) {
raw = raw || {};
const name = raw.name || raw.file_name || raw.title || '';
return String(raw.id || raw.file_id || raw.fileId || raw.resource_id || raw.resourceId || `share_${parentId || 'root'}_${index}_${name}`);
}

function getSharePathText(pathNodes) {
const L = getStrings();
const nodes = (Array.isArray(pathNodes) ? pathNodes : []).filter(n => n && !n._sharePanel);
const text = nodes.map(n => n.name || '').filter(Boolean).join(' / ');
return text || L.label_share_parse_path_root;
}

function normalizeSharePathSearchText(text) {
return String(text || '').toLowerCase().replace(/[\\／]+/g, '/').replace(/\s*\/\s*/g, '/');
}

function mapShareInsightFile(file, index, pathNodes, parentId) {
const raw = file || {};
const id = getShareDetailFileId(raw, parentId, index);
const name = raw.name || raw.file_name || raw.title || '';
const mime = raw.mime_type || raw.mimeType || raw.content_type || '';
const source = {
...raw,
id,
kind: 'drive#file',
name,
parent_id: parentId || raw.parent_id || raw.parentId || '',
size: raw.size || raw.file_size || 0,
mime_type: mime,
thumbnail_link: raw.thumbnail_link || raw.thumbnailLink || raw.thumbnail || '',
icon_link: raw.icon_link || raw.iconLink || raw.icon || '',
modified_time: raw.modified_time || raw.modifiedTime || raw.updated_time || raw.created_time || '',
hash: raw.hash || raw.gcid || raw.md5_checksum || '',
tags: [],
starred: false,
trashed: false,
_pkSkipDurationProbe: true
};
const mapped = minifyFile(source, false);
const curPath = Array.isArray(pathNodes) && pathNodes.length ? pathNodes.slice() : buildShareParseRootPath();
const ancestorIds = curPath.map(n => n && n.id).filter(idv => idv && idv !== 'share_parse_panel');
const pathText = getSharePathText(curPath);
return Object.assign(mapped, {
_isShareItem: true,
_isShareInsightItem: true,
_shareId: (S.shareParseInfo && S.shareParseInfo.share_id) || '',
_passCodeToken: (S.shareParseInfo && S.shareParseInfo.pass_code_token) || '',
_shareParentId: parentId || raw.parent_id || raw.parentId || '',
_shareAncestorIds: ancestorIds,
_sharePath: curPath,
_shareFilePathText: pathText,
_rawShareFile: raw,
_pkSkipDurationProbe: true
});
}

async function scanShareParseInsight(reqId, targets = null, silent = false) {
const currentPath = Array.isArray(S.shareParsePath) && S.shareParsePath.length ? S.shareParsePath.slice() : buildShareParseRootPath();
const currentParentId = S.shareParseCurParentId || getShareParseRootParentId();
const selected = Array.isArray(targets) ? targets.filter(item => item && item._isShareItem && item.id) : [];
const queue = [];
const result = [];
const resultKeys = new Set();
const pushInsightFile = (file, pathNodes, parentId) => {
const item = mapShareInsightFile(file, result.length, pathNodes, parentId || '');
const key = `${item._shareParentId || parentId || ''}/${item.id || item.name || result.length}`;
if (resultKeys.has(key)) return;
resultKeys.add(key);
result.push(item);
};
if (selected.length) {
selected.forEach(item => {
const parentId = item._shareParentId || item.parent_id || '';
const itemPath = Array.isArray(item._sharePath) && item._sharePath.length ? item._sharePath.slice() : (item.kind === 'drive#folder' ? currentPath.concat([{ id: item.id, name: item.name || '', parent_id: parentId }]) : currentPath);
if (item.kind === 'drive#folder') queue.push({ id: item.id, path: itemPath });
else pushInsightFile(item._rawShareFile || item, itemPath, parentId);
});
} else {
queue.push({ id: currentParentId || '', path: currentPath });
}
let scannedFolders = 0;
const startedAt = Date.now();
const syncInsightProgress = () => {
S.shareParseInsightProgress = { folder: scannedFolders, file: result.length };
if (silent) {
const sec = Math.max(1, Math.round((Date.now() - startedAt) / 1000));
const speed = Math.max(1, Math.round(scannedFolders / sec));
updateLoadTxt(`${L.str_scanning} ${scannedFolders} ${L.unit_folders} | ${L.str_files}: ${result.length} | ${L.str_speed}: ${speed}`);
} else {
S.shareParseInsightItems = result.slice();
S.shareParseInsightDisplay = S.shareParseInsightItems.slice();
syncShareParseInsightMirror();
renderShareParseCurrentView();
}
};

const canContinueShareParseInsight = () => S.shareParseMode && (silent || S.shareParseInsightMode) && S.shareParseInsightReqId === reqId && !S.shareParseInsightStop;
const scanConcurrency = Math.max(1, Math.min(128, parseInt(CONF.shareParseInsightConcurrency || 128, 10) || 128));
const scanShareParseInsightFolder = async (node) => {
const parentId = node.id || '';
const directItems = [];
const consumeCachedItems = (items) => {
(Array.isArray(items) ? items : []).forEach((item, idx) => {
const raw = item && item._rawShareFile ? item._rawShareFile : item;
const itemId = item && item.id ? item.id : getShareDetailFileId(raw, parentId, idx);
const name = (item && item.name) || (raw && (raw.name || raw.file_name || raw.title)) || '';
if ((item && item.kind === 'drive#folder') || isShareDetailFolder(raw)) {
const itemPath = Array.isArray(item && item._sharePath) && item._sharePath.length ? S.cloneShareParsePath(item._sharePath) : node.path.concat([{ id: itemId, name, parent_id: parentId }]);
queue.push({ id: itemId, path: itemPath });
} else {
pushInsightFile(raw || item, node.path, parentId);
}
});
};
const consumeRawFiles = (files) => {
const baseIndex = directItems.length;
(Array.isArray(files) ? files : []).forEach((file, idx) => {
const cacheItem = mapShareDetailFile(file, baseIndex + idx, { parentId, path: node.path });
directItems.push(cacheItem);
const itemId = getShareDetailFileId(file, parentId, baseIndex + idx);
const name = file.name || file.file_name || file.title || '';
if (isShareDetailFolder(file)) {
queue.push({ id: itemId, path: node.path.concat([{ id: itemId, name, parent_id: parentId }]) });
} else {
pushInsightFile(file, node.path, parentId);
}
});
};

let pageToken = '';
const cached = readShareParseFolderCache(parentId);
if (cached) {
directItems.push(...cached.items);
consumeCachedItems(cached.items);
pageToken = cached.nextPageToken || '';
syncInsightProgress();
if (!pageToken) {
scannedFolders++;
syncInsightProgress();
return;
}
}

do {
if (!canContinueShareParseInsight()) break;
const raw = await fetchShareDetail(parentId, pageToken || '');
if (!canContinueShareParseInsight()) break;
consumeRawFiles(getShareDetailFiles(raw));
syncInsightProgress();
pageToken = getShareDetailNextToken(raw);
writeShareParseFolderCacheEntry(parentId, node.path, directItems, pageToken || '');
if (pageToken) await sleep(30);
} while (pageToken && canContinueShareParseInsight());
scannedFolders++;
syncInsightProgress();
};

await new Promise((resolve, reject) => {
let running = 0;
let settled = false;
const pump = () => {
if (settled) return;
if (!canContinueShareParseInsight()) {
settled = true;
resolve();
return;
}
while (running < scanConcurrency && queue.length && canContinueShareParseInsight()) {
const node = queue.shift();
running++;
scanShareParseInsightFolder(node).then(() => {
running--;
pump();
}).catch(err => {
if (settled) return;
settled = true;
reject(err);
});
}
if (!queue.length && running === 0) {
settled = true;
resolve();
}
};
pump();
});

return result;
}

function filterShareParseInsightItemsByScanRule(items, scanFilter) {
const src = Array.isArray(items) ? items.slice() : [];
const rawTotal = src.length;
const hasActiveFilter = !!(scanFilter && ((scanFilter.keyword || '').trim() || scanFilter.minBytes > 0 || scanFilter.maxBytes > 0));
if (!hasActiveFilter) return { items: src, rawTotal, hasActiveFilter };
const kwList = String(scanFilter.keyword || '').toLowerCase().split(/[,，]/).map(k => k.trim()).filter(k => k);
const minBytes = Math.max(0, parseInt(scanFilter.minBytes || 0, 10) || 0);
const maxBytes = Math.max(0, parseInt(scanFilter.maxBytes || 0, 10) || 0);
return { items: src.filter(item => {
if (kwList.length > 0) {
const fullLowerName = String(item && item.name || '').toLowerCase();
const lastDot = fullLowerName.lastIndexOf('.');
const nameWithoutExt = lastDot > 0 ? fullLowerName.substring(0, lastDot) : fullLowerName;
if (kwList.some(k => nameWithoutExt.includes(k))) return false;
}
const sz = parseInt(item && item.size || 0, 10) || 0;
if (sz < minBytes) return false;
if (maxBytes > 0 && sz > maxBytes) return false;
return true;
}), rawTotal, hasActiveFilter };
}

