function clearShareParseAutoPagingResumeTimer() {
if (S.shareParseAutoLoadRetryTimer) {
clearTimeout(S.shareParseAutoLoadRetryTimer);
S.shareParseAutoLoadRetryTimer = 0;
}
}

function cancelShareParseAutoPaging() {
S.shareParseAutoLoadToken = (S.shareParseAutoLoadToken || 0) + 1;
S.shareParseAutoLoadRunning = false;
S.shareParseAutoLoadTarget = '';
S.shareParseAutoLoadInterrupted = false;
S.shareParseAutoLoadResumeTarget = '';
S.shareParseAutoLoadRegionBlocked = false;
S.shareParseRegionResumeCtx = null;
clearShareParseAutoPagingResumeTimer();
}

function isShareParseRecoverableNetworkError(e) {
if (typeof navigator !== 'undefined' && navigator.onLine === false) return true;
const key = String((e && e.shareParseKey) || '');
if (key === 'msg_share_parse_network_error') return true;
const name = String((e && e.name) || '');
if (name === 'AbortError') return true;
if (name === 'TypeError' && !(e && e.shareParseKey)) return true;
return false;
}

function isShareParseRegionUnavailableError(e) {
return String((e && e.shareParseKey) || '') === 'msg_share_parse_region_unavailable';
}

function scheduleShareParseRegionResumeProbe(delay = 5000) {
clearShareParseAutoPagingResumeTimer();
if (!(S.shareParseMode && S.shareParseAutoLoadRegionBlocked)) return;
S.shareParseAutoLoadRetryTimer = setTimeout(() => {
S.shareParseAutoLoadRetryTimer = 0;
resumeShareParseAutoPagingAfterNetworkBack();
if (S.shareParseAutoLoadRegionBlocked) scheduleShareParseRegionResumeProbe(8000);
}, Math.max(1200, Number(delay) || 5000));
}

function markShareParseAutoPagingInterrupted(parentId = '', reason = 'network') {
S.shareParseAutoLoadInterrupted = true;
S.shareParseAutoLoadResumeTarget = String(parentId || S.shareParseCurParentId || '');
S.shareParseAutoLoadRunning = false;
S.shareParseAutoLoadRegionBlocked = reason === 'region';
S.pagingLoading = false;
updateStat();
if (S.shareParseAutoLoadRegionBlocked) scheduleShareParseRegionResumeProbe();
}

function resumeShareParseAutoPagingAfterNetworkBack() {
if (!(S.shareParseMode && S.shareParseListActive && !S.shareParseInsightMode)) return;
if (S.shareParseAutoLoadRunning || S.shareParseListLoading) return;
if (typeof navigator !== 'undefined' && navigator.onLine === false) return;
if (S.shareParseRegionResumeCtx) {
const ctx = S.shareParseRegionResumeCtx;
S.shareParseRegionResumeCtx = null;
loadShareParseFolder(ctx.folderNode || null, Object.assign({}, ctx.opts || {}, { forceReload: true })).catch(() => {});
return;
}
if (!S.shareParseNextPageToken) return;
scheduleShareParseAutoPaging(S.shareParseAutoLoadResumeTarget || S.shareParseCurParentId || '', { force: true });
}

function scheduleShareParseAutoPaging(parentId = '', opts = {}) {
if (!S.shareParseMode || S.shareParseInsightMode || !S.shareParseListActive || !S.shareParseNextPageToken) return;
if (S.shareParseAutoLoadInterrupted && !(opts && opts.force)) return;
S.shareParseAutoLoadInterrupted = false;
S.shareParseAutoLoadResumeTarget = '';
S.shareParseAutoLoadRegionBlocked = false;
clearShareParseAutoPagingResumeTimer();
S.pagingLoading = true;
updateStat();
const target = String(parentId || S.shareParseCurParentId || '');
if (S.shareParseAutoLoadRunning && S.shareParseAutoLoadTarget === target) return;
const token = (S.shareParseAutoLoadToken || 0) + 1;
S.shareParseAutoLoadToken = token;
S.shareParseAutoLoadTarget = target;
setTimeout(() => drainShareParseAutoPaging(token, target).catch(() => {}), 0);
}

async function drainShareParseAutoPaging(token, target) {
S.shareParseAutoLoadRunning = true;
try {
while (
S.shareParseAutoLoadToken === token &&
S.shareParseMode &&
S.shareParseListActive &&
!S.shareParseInsightMode &&
!S.shareParseAutoLoadInterrupted &&
String(S.shareParseCurParentId || '') === String(target || '') &&
S.shareParseNextPageToken
) {
if (S.shareParseListLoading) {
await sleep(80);
continue;
}
await loadShareParseFolder(null, { append: true, autoPaging: true });
await sleep(30);
}
} finally {
if (S.shareParseAutoLoadToken === token) {
S.shareParseAutoLoadRunning = false;
S.shareParseAutoLoadTarget = '';
S.pagingLoading = !!(S.shareParseMode && S.shareParseListActive && !S.shareParseInsightMode && S.shareParseNextPageToken && !S.shareParseAutoLoadInterrupted);
updateStat();
}
}
}

if (!window.__pkShareParseAutoPagingResumeBound) {
window.__pkShareParseAutoPagingResumeBound = true;
window.addEventListener('online', resumeShareParseAutoPagingAfterNetworkBack);
window.addEventListener('focus', resumeShareParseAutoPagingAfterNetworkBack);
window.addEventListener('pageshow', resumeShareParseAutoPagingAfterNetworkBack);
document.addEventListener('visibilitychange', () => {
if (!document.hidden) resumeShareParseAutoPagingAfterNetworkBack();
});
}

async function loadShareParseFolder(folderNode = null, opts = {}) {
const L = getStrings();
if (!S.shareParseMode) return false;
const append = !!opts.append;
const forceReload = !!opts.forceReload;
const deferActivate = !!opts.deferActivate && !append;
if (!append) cancelShareParseAutoPaging();
if (!append && S.shareParseInsightMode) resetShareParseInsightState(true);
if (append && (!S.shareParseListActive || !S.shareParseNextPageToken || S.shareParseListLoading)) return false;
const parentId = append ? (S.shareParseCurParentId || '') : (folderNode && folderNode.id ? folderNode.id : getShareParseRootParentId());
const pageToken = append ? S.shareParseNextPageToken : '';
const targetPathForNav = (!append && folderNode && Array.isArray(folderNode._sharePath) && folderNode._sharePath.length) ? S.cloneShareParsePath(folderNode._sharePath) : (!append ? buildShareParseRootPath() : null);
const shouldRecordShareParseNav = !append && !opts.suppressShareParseNav && !S.shareParseNavSuspendRecord && !S.browserNavRestoring && S.shareParseListActive && !S.shareParseInsightMode;
const prevShareParseNavSnap = shouldRecordShareParseNav ? S.makeShareParseNavSnapshot() : null;
const recordedShareParseNav = !!(prevShareParseNavSnap && targetPathForNav && !S.isSameShareParsePath(prevShareParseNavSnap.path, targetPathForNav) && S.pushShareParseNavSnapshot(prevShareParseNavSnap, true));
const reqId = (S.shareParseListReqId || 0) + 1;
S.shareParseListReqId = reqId;
if (!deferActivate) S.shareParseListActive = true;
if (!append && !deferActivate && typeof applyResolvedViewMode === 'function') applyResolvedViewMode('share_parse_list');
S.shareParseListLoading = true;
S.shareParseListError = '';
S.shareParseCurParentId = parentId || '';
S.pagingLoading = !!append;
if (append) updateStat();

if (!append && !forceReload) {
const cached = readShareParseFolderCache(parentId || '');
if (cached) {
S.shareParseListActive = true;
if (typeof applyResolvedViewMode === 'function') applyResolvedViewMode('share_parse_list');
S.shareParseItems = cached.items;
S.shareParseDisplay = S.shareParseItems.slice();
S.shareParseItemMap = new Map();
S.shareParseItems.forEach(item => { if (item && item.id) S.shareParseItemMap.set(item.id, item); });
S.shareParsePath = cached.path.length ? cached.path : (targetPathForNav ? S.cloneShareParsePath(targetPathForNav) : buildShareParseRootPath());
S.shareParseCurParentId = cached.parentId || parentId || '';
S.shareParseNextPageToken = cached.nextPageToken || '';
S.shareParseListLoading = false;
S.pagingLoading = !!S.shareParseNextPageToken;
S.sel.clear();
S.selEx.clear();
S.selMode = 'explicit';
S.activeId = null;
S.lastSelIdx = -1;
syncShareParseMirror();
renderShareParseCurrentView();
restoreShareParseFolderScroll(opts, false);
if (!append && !opts.suppressShareParseNav && !S.browserNavRestoring && S.shareParseMode && S.shareParseListActive && !S.shareParseInsightMode) S.syncShareParseBrowserNavState(recordedShareParseNav ? 'push' : 'replace');
scheduleShareParseAutoPaging(S.shareParseCurParentId || parentId || '');
return true;
}
}

if (!append) {
S.shareParseItems = [];
S.shareParseDisplay = [];
S.shareParseItemMap = new Map();
S.shareParseNextPageToken = '';
S.sel.clear();
S.selEx.clear();
S.selMode = 'explicit';
S.activeId = null;
S.lastSelIdx = -1;
if (folderNode && Array.isArray(folderNode._sharePath) && folderNode._sharePath.length) {
S.shareParsePath = folderNode._sharePath.slice();
} else {
S.shareParsePath = buildShareParseRootPath();
}
}

if (!deferActivate) syncShareParseMirror();
renderShareParseCurrentView();

let ok = false;
try {
const raw = await fetchShareDetail(parentId || '', pageToken || '');
if (!S.shareParseMode || S.shareParseListReqId !== reqId) return false;
const mapped = getShareDetailFiles(raw).map((file, idx) => mapShareDetailFile(file, idx));
if (deferActivate) {
S.shareParseListActive = true;
if (typeof applyResolvedViewMode === 'function') applyResolvedViewMode('share_parse_list');
}
S.shareParseItems = append ? S.shareParseItems.concat(mapped) : mapped;
S.shareParseDisplay = S.shareParseItems.slice();
S.shareParseItemMap = new Map();
S.shareParseItems.forEach(item => { if (item && item.id) S.shareParseItemMap.set(item.id, item); });
S.shareParseNextPageToken = getShareDetailNextToken(raw);
S.shareParseListError = '';
S.shareParseAutoLoadInterrupted = false;
S.shareParseAutoLoadResumeTarget = '';
S.shareParseAutoLoadRegionBlocked = false;
S.shareParseRegionResumeCtx = null;
writeShareParseFolderCache(parentId || '');
ok = true;
} catch(e) {
if (!S.shareParseMode || S.shareParseListReqId !== reqId) return false;
const msg = getShareParseErrorMessage(e) || L.msg_share_parse_load_failed;
const isRegionBlocked = isShareParseRegionUnavailableError(e);
S.shareParseListError = msg;
if (!append) {
S.shareParseItems = [];
S.shareParseDisplay = [];
S.shareParseItemMap = new Map();
if (isRegionBlocked) {
const retryFolderNode = folderNode ? Object.assign({}, folderNode, { _sharePath: Array.isArray(folderNode._sharePath) ? S.cloneShareParsePath(folderNode._sharePath) : folderNode._sharePath }) : null;
S.shareParseRegionResumeCtx = { folderNode: retryFolderNode, opts: { append: false, forceReload: true, deferActivate } };
markShareParseAutoPagingInterrupted(parentId || '', 'region');
} else {
S.shareParseAutoLoadInterrupted = false;
S.shareParseAutoLoadResumeTarget = '';
S.shareParseAutoLoadRegionBlocked = false;
S.shareParseRegionResumeCtx = null;
}
} else if (isRegionBlocked) {
S.shareParseNextPageToken = pageToken || S.shareParseNextPageToken || '';
markShareParseAutoPagingInterrupted(parentId || '', 'region');
} else if (isShareParseRecoverableNetworkError(e)) {
S.shareParseNextPageToken = pageToken || S.shareParseNextPageToken || '';
markShareParseAutoPagingInterrupted(parentId || '');
} else {
S.shareParseNextPageToken = '';
S.shareParseAutoLoadInterrupted = false;
S.shareParseAutoLoadResumeTarget = '';
S.shareParseAutoLoadRegionBlocked = false;
S.shareParseRegionResumeCtx = null;
}
if (!isRegionBlocked || Date.now() - Number(S.shareParseRegionUnavailableToastAt || 0) > 12000) {
showToast(msg, 'error');
if (isRegionBlocked) S.shareParseRegionUnavailableToastAt = Date.now();
}
} finally {
if (S.shareParseListReqId === reqId) {
S.shareParseListLoading = false;
S.pagingLoading = !!(S.shareParseMode && S.shareParseListActive && !S.shareParseInsightMode && S.shareParseNextPageToken && !S.shareParseAutoLoadInterrupted);
if (S.shareParseMode) renderShareParseCurrentView();
restoreShareParseFolderScroll(opts, append);
if (!append && S.shareParseMode && S.shareParseListReqId === reqId && !S.shareParseAutoLoadRegionBlocked) scheduleShareParseAutoPaging(parentId || '');
}
}
if (ok && !append && !opts.suppressShareParseNav && !S.browserNavRestoring && S.shareParseMode && S.shareParseListActive && !S.shareParseInsightMode) S.syncShareParseBrowserNavState(recordedShareParseNav ? 'push' : 'replace');
return ok;
}


function loadShareParseNextPage() {
return loadShareParseFolder(null, { append: true });
}

function maybeLoadShareParseNextPage() {
if (S.shareParseInsightMode) return;
scheduleShareParseAutoPaging(S.shareParseCurParentId || '', { force: true });
}

const AUDIO_FILE_EXTS = new Set(['mp3','wav','flac','aac','m4a','ogg','opus','ape','wma','amr','m4b','alac','aiff','aif','mid','midi','ra','dts','ac3','dsf','dff']);

function getItemExt(it) {
const name = String((it && it.name) || '').toLowerCase();
const m = name.match(/\.([^.\/\\]+)$/);
return m ? m[1] : '';
}

function isAudioLikeItem(it) {
if (!it || it.isHeader || it.kind === 'drive#folder') return false;
const m = String((it && it.mime_type) || '').toLowerCase();
return m.startsWith('audio/') || AUDIO_FILE_EXTS.has(getItemExt(it));
}

function getAudioDirectUrl(detail) {
if (!detail) return '';
if (detail.web_content_link) return detail.web_content_link;
const oct = detail.links && detail.links['application/octet-stream'];
return (oct && oct.url) || '';
}

function getAudioPhysicalId(it) {
if (!it) return '';
if ((S.offlineMode && it.kind === 'drive#task') || (S.uploadMode && it.file_id)) return it.file_id || it.id || '';
return it.id || '';
}

function isVideoLikeItem(it) {
if (isAudioLikeItem(it)) return false;
const m = String((it && it.mime_type) || '').toLowerCase();
const n = String((it && it.name) || '').toLowerCase();
const dur = Number((it && it.params && it.params.duration) || 0);
return m.startsWith('video/') || dur > 0 || ['mp4','mkv','avi','mov','wmv','flv','webm','ts','m4v','3gp'].some(e => n.endsWith('.' + e));
}

function isImageLikeItem(it) {
const m = String((it && it.mime_type) || '').toLowerCase();
const n = String((it && it.name) || '').toLowerCase();
return m.startsWith('image/') || ['jpg','jpeg','png','gif','webp','bmp','avif'].some(e => n.endsWith('.' + e));
}

function isArchiveLike(it) {
const m = String((it && it.mime_type) || '').toLowerCase();
const n = String((it && it.name) || '').toLowerCase();
return m.includes('zip') || m.includes('rar') || m.includes('archive') || ['zip','rar','7z','tar','gz','bz2','xz'].some(e => n.endsWith('.' + e));
}

let activeTextPreviewReqId = 0;
let activeShareTextPreviewFileId = '';
const textPreviewStateMap = new WeakMap();

function isTxtFileLike(it) {
if (!it || it.isHeader || it.kind === 'drive#folder') return false;
const ext = String((it && it.file_extension) || '').toLowerCase();
const m = String((it && it.mime_type) || '').toLowerCase();
return ext === '.txt' || getItemExt(it) === 'txt' || m.includes('text/plain');
}

function showUnsupportedOpenToast() {
const L = getStrings();
showToast(L.msg_open_download_after, 'warning');
}

function getTextDirectUrlFromFileInfo(fileInfo) {
if (!fileInfo) return '';
if (fileInfo.web_content_link) return fileInfo.web_content_link;
const oct = fileInfo.links && fileInfo.links['application/octet-stream'];
return (oct && oct.url) || '';
}

function makeTextPreviewError(code, cause = null) {
const err = new Error(code || 'txt_preview_load_failed');
err.code = code || 'load_failed';
if (cause) err.cause = cause;
return err;
}

function stripTextBom(text) {
return text && text.charCodeAt(0) === 0xFEFF ? text.slice(1) : text;
}

function decodeUtf16Bytes(bytes, littleEndian, offset = 0) {
let out = '';
let chunk = [];
const flush = () => {
if (chunk.length) {
out += String.fromCharCode.apply(null, chunk);
chunk = [];
}
};
for (let i = offset; i + 1 < bytes.length; i += 2) {
const code = littleEndian ? (bytes[i] | (bytes[i + 1] << 8)) : ((bytes[i] << 8) | bytes[i + 1]);
chunk.push(code);
if (chunk.length >= 8192) flush();
}
flush();
return stripTextBom(out);
}

function tryDecodeText(bytes, label) {
try {
return stripTextBom(new TextDecoder(label).decode(bytes));
} catch(e) {
return null;
}
}

function getTextDecodeScore(text) {
if (!text) return 0;
let bad = 0;
for (let i = 0; i < text.length; i++) {
const code = text.charCodeAt(i);
if (code === 0xFFFD) bad += 1;
else if ((code < 32 && code !== 9 && code !== 10 && code !== 13) || code === 127) bad += 0.4;
}
return bad / Math.max(1, text.length);
}

function decodeTextArrayBuffer(buffer) {
const bytes = new Uint8Array(buffer || new ArrayBuffer(0));
if (!bytes.byteLength) return { text: '', encoding: '' };
if (bytes.length >= 3 && bytes[0] === 0xEF && bytes[1] === 0xBB && bytes[2] === 0xBF) {
const text = tryDecodeText(bytes.subarray(3), 'utf-8');
if (text !== null) return { text, encoding: 'utf-8-bom' };
}
if (bytes.length >= 2 && bytes[0] === 0xFF && bytes[1] === 0xFE) return { text: decodeUtf16Bytes(bytes, true, 2), encoding: 'utf-16le' };
if (bytes.length >= 2 && bytes[0] === 0xFE && bytes[1] === 0xFF) return { text: decodeUtf16Bytes(bytes, false, 2), encoding: 'utf-16be' };

const attempts = [];
const utf8 = tryDecodeText(bytes, 'utf-8');
if (utf8 !== null) {
const score = getTextDecodeScore(utf8);
if (score <= 0.001) return { text: utf8, encoding: 'utf-8' };
attempts.push({ text: utf8, encoding: 'utf-8', score });
}

['gb18030','gbk','big5','shift_jis','euc-kr','windows-1252'].forEach(label => {
const text = tryDecodeText(bytes, label);
if (text !== null) attempts.push({ text, encoding: label, score: getTextDecodeScore(text) });
});
attempts.sort((a, b) => a.score - b.score);
const best = attempts[0];
if (!best || best.score > 0.25) throw makeTextPreviewError('decode_failed');
return { text: best.text, encoding: best.encoding };
}

async function readTextFromDirectUrl(url, fileInfo) {
if (!url) throw makeTextPreviewError('load_failed');
const size = Number(fileInfo && fileInfo.size);
if (Number.isFinite(size) && size > CONF.textPreviewMaxBytes) throw makeTextPreviewError('too_large');
let res;
try {
res = await fetch(url);
} catch(e) {
throw makeTextPreviewError('load_failed', e);
}
if (!res || !res.ok) throw makeTextPreviewError('load_failed');
const contentLength = Number(res.headers && res.headers.get ? (res.headers.get('content-length') || 0) : 0);
if (Number.isFinite(contentLength) && contentLength > CONF.textPreviewMaxBytes) throw makeTextPreviewError('too_large');
let buffer;
try {
buffer = await res.arrayBuffer();
} catch(e) {
throw makeTextPreviewError('load_failed', e);
}
if (!buffer || buffer.byteLength === 0) return '';
if (buffer.byteLength > CONF.textPreviewMaxBytes) throw makeTextPreviewError('too_large');
try {
return decodeTextArrayBuffer(buffer).text;
} catch(e) {
if (e && e.code === 'decode_failed') throw e;
throw makeTextPreviewError('decode_failed', e);
}
}

async function readTextFromFileInfo(fileInfo) {
const url = getTextDirectUrlFromFileInfo(fileInfo);
if (!url) throw makeTextPreviewError('load_failed');
return readTextFromDirectUrl(url, fileInfo);
}

function getTextPreviewState(modal) {
return modal ? textPreviewStateMap.get(modal) : null;
}

function formatTextPreviewShortcutLabel(label, shortcut) {
return shortcut ? `${label} (${shortcut})` : label;
}

function setTextPreviewButtonTip(btn, label) {
if (!btn || !label) return;
btn.setAttribute('aria-label', label);
btn.setAttribute('data-pk-tip', label);
btn.removeAttribute('title');
}

function setupTextPreviewShortcutKeys(modal) {
if (!modal) return;
modal.tabIndex = 0;
setTimeout(() => { if (document.contains(modal)) modal.focus(); }, 10);
modal.addEventListener('keydown', (e) => {
const target = e.target;
const tag = String(target && target.tagName || '').toLowerCase();
if (target && (target.isContentEditable || tag === 'input' || tag === 'textarea' || tag === 'select')) return;
const key = String(e.key || '').toLowerCase();
if (e.key === 'Escape') {
e.preventDefault();
e.stopPropagation();
modal.querySelector('.pk-modal-close')?.click();
return;
}
if (key === 'f' && !e.ctrlKey && !e.altKey && !e.metaKey) {
e.preventDefault();
e.stopPropagation();
modal.querySelector('#pk_txt_preview_fullscreen')?.click();
return;
}
if (e.key === 'Enter' && e.ctrlKey && !e.altKey && !e.metaKey) {
const parseBtn = modal.querySelector('#pk_txt_preview_parse_links');
if (parseBtn && parseBtn.style.display !== 'none' && !parseBtn.disabled) {
e.preventDefault();
e.stopPropagation();
parseBtn.click();
}
}
}, true);
}

function cleanupTextPreviewModal(modal) {
const state = getTextPreviewState(modal);
if (state) {
state.text = '';
state.loading = false;
state.parsingLinks = false;
}
document.documentElement.classList.remove('pk-txt-preview-fullscreen-lock');
document.body.classList.remove('pk-txt-preview-fullscreen-lock');
if (modal) textPreviewStateMap.delete(modal);
}

function getTextPreviewDefaultCloudTarget() {
const path = Array.isArray(S.path) ? S.path : [];
const curFolder = path[path.length - 1] || {};
const curId = String(curFolder.id || '');
const isVirtual = curId.startsWith('virtual_') || curId.includes('_root') || curId === 'analyze_root';
const isHomeSubDir = !S.trashMode && !S.shareMode && !S.shareParseMode && !S.offlineMode && !S.uploadMode && !S.starredMode && !S.recentMode && !S.historyMode && !S.isFlattened && !S.dupMode && path.length > 1 && !isVirtual;
const L = getStrings();
return { id: isHomeSubDir ? curId : '', name: isHomeSubDir ? (curFolder.name || L.lbl_default_folder) : L.lbl_default_folder, path: isHomeSubDir ? path.filter(p => !String(p.id || '').startsWith('virtual_')) : null };
}

function isCloudTaskRateLimited(reqErr) {
const errText = String((reqErr && (reqErr.message || reqErr.status || reqErr.code)) || '');
return errText.includes('429');
}

async function apiAddOfflineTaskWithRetry(url, targetId = '', extraParams = {}) {
let retry = 0;
while (retry < 3) {
try {
return await apiAddOfflineTask(url, targetId || '', extraParams || {});
} catch (reqErr) {
if (isCloudTaskRateLimited(reqErr)) {
retry++;
if (retry >= 3) throw reqErr;
await sleep(2000 * retry);
} else {
throw reqErr;
}
}
}
return null;
}

function refreshCloudTaskView(targetId = '', options = {}) {
setTimeout(() => updateQuotaUI(), 1000);
const path = Array.isArray(S.path) ? S.path : [];
const curPathId = (path[path.length - 1] && path[path.length - 1].id) || '';
if (S.offlineMode) {
if (options.skipOfflineProbe === true) return;
scheduleOfflineTaskAddProbe(options.reason || 'add', options.delay || 1000);
return;
} else if (targetId && curPathId === targetId) {
load(false, true);
} else if (!targetId && path.length === 1) {
if (window.pkSmartRefreshTrigger) window.pkSmartRefreshTrigger(true);
}
}

