const getTooltipHlHTML = (text, query) => {
if (!query || !shouldShowHl) return esc(text);
const lowText = text.toLowerCase();
const q = query.toLowerCase();
const idx = lowText.indexOf(q);
if (idx === -1) return esc(text);
return esc(text.substring(0, idx)) + `<b style="color:var(--pk-match-fg); background:var(--pk-match-bg); border-radius:2px; padding:0 2px;">${esc(text.substring(idx, idx + q.length))}</b>` + getTooltipHlHTML(text.substring(idx + q.length), query);
};

const getSearchHlHTML = (name, query, capacity) => {
const q = query.toLowerCase();
const idx = name.toLowerCase().indexOf(q);
if (idx === -1) return esc(name);

let start = 0, end = name.length, prefix = "", suffix = "";
if (name.length > capacity) {
const preLimit = Math.floor(capacity * 0.3);
start = Math.max(0, idx - preLimit);
end = Math.min(name.length, start + capacity);
if (start > 0) prefix = "...";
if (end < name.length) suffix = "...";
}

const targetSlice = name.substring(start, end);
return prefix + getTooltipHlHTML(targetSlice, query) + suffix;
};

const getSharePathSearchHlHTML = (text, query, capacity) => {
const raw = String(text || '');
const q = normalizeSharePathSearchText(query);
if (!q) return esc(raw);
let norm = '', map = [], slash = false;
for (let i = 0; i < raw.length; i++) {
const ch = raw[i];
if (/[\\/／]/.test(ch)) {
while (norm.endsWith(' ')) {
norm = norm.slice(0, -1);
map.pop();
}
norm += '/';
map.push(i);
slash = true;
continue;
}
if (slash && /\s/.test(ch)) continue;
slash = false;
norm += ch.toLowerCase();
map.push(i);
}
const idx = norm.indexOf(q);
if (idx === -1 || !map[idx] && map[idx] !== 0) return getSearchHlHTML(raw, query, capacity);
const matchStart = map[idx];
const matchEnd = (map[idx + q.length - 1] ?? matchStart) + 1;
let start = 0, end = raw.length, prefix = '', suffix = '';
if (raw.length > capacity) {
const cap = Math.max(q.length + 8, Math.floor(capacity || 30));
const preLimit = Math.max(0, Math.floor((cap - (matchEnd - matchStart)) * 0.3));
start = Math.max(0, matchStart - preLimit);
end = Math.min(raw.length, start + cap);
if (end < matchEnd) {
end = matchEnd;
start = Math.max(0, end - cap);
}
if (start > 0) prefix = '...';
if (end < raw.length) suffix = '...';
}
const hiStart = Math.max(matchStart, start);
const hiEnd = Math.min(matchEnd, end);
return prefix + esc(raw.substring(start, hiStart)) + `<b style="color:var(--pk-match-fg); background:var(--pk-match-bg); border-radius:2px; padding:0 2px;">${esc(raw.substring(hiStart, hiEnd))}</b>` + esc(raw.substring(hiEnd, end)) + suffix;
};

const getGridSearchHlHTML = (name, query, capacity) => {
const text = String(name || '');
const q = String(query || '').toLowerCase();
if (!q) return esc(text);
const idx = text.toLowerCase().indexOf(q);
if (idx === -1) return esc(text);
const cap = Math.max(q.length + 8, Math.floor(capacity || 18));
if (text.length <= cap && idx + q.length <= cap - 1) return getTooltipHlHTML(text, query);
const preLimit = Math.max(3, Math.floor((cap - q.length) * 0.45));
let start = Math.max(0, idx - preLimit);
let end = Math.min(text.length, start + cap);
if (end - start < cap) start = Math.max(0, end - cap);
const prefix = start > 0 ? "..." : "";
const suffix = end < text.length ? "..." : "";
return prefix + getTooltipHlHTML(text.substring(start, end), query) + suffix;
};

