const takeGridStableRow = (itemId) => {
if (!itemId || gridPassUsedIds.has(itemId)) {
return { row: takeGridFallbackRow(), duplicate: true };
}

gridPassUsedIds.add(itemId);

const rowMap = UI.in._pkGridRowMap;
let row = rowMap.get(itemId) || null;
const isReservedGridRow = (candidate) => {
if (!candidate || !candidate.dataset) return false;
const boundId = candidate.dataset.pkBoundId || '';
return !!(boundId && boundId !== itemId && rowMap.get(boundId) === candidate);
};

if (row && (row._pkGridUsedThisPass || gridPassUsedRows.has(row) || !row._pkPooledRow)) {
row = null;
}

if (!row) {
row = rowPool.find(r => r && !r._pkGridUsedThisPass && !gridPassUsedRows.has(r) && (r.dataset.pkBoundId || '') === itemId)
|| rowPool.find(r => r && !r._pkGridUsedThisPass && !gridPassUsedRows.has(r) && r.parentNode !== UI.in && !isReservedGridRow(r))
|| rowPool.find(r => r && !r._pkGridUsedThisPass && !gridPassUsedRows.has(r) && !isReservedGridRow(r));
}

if (!row) {
row = document.createElement('div');
row._pkPooledRow = true;
row.style.position = 'absolute';
rowPool.push(row);
}

const oldId = row.dataset.pkBoundId || '';
if (oldId && oldId !== itemId && rowMap.get(oldId) === row) {
rowMap.delete(oldId);
}

rowMap.set(itemId, row);
row._pkGridUsedThisPass = true;
gridPassUsedRows.add(row);
poolPtr++;
return { row, duplicate: false };
};

const getGridFolderCountSig = (item) => {
if (!item || item.kind !== 'drive#folder' || S.trashMode) return '';

let count = item.file_count;
if (count === undefined || count === null) count = item.usage?.file_count;
if (count === undefined || count === null) count = item.params?.file_count;
if (count === undefined || count === null) count = item.audit?.file_count;

if ((count === undefined || count === null) && !item._isShareItem && typeof globalCache !== 'undefined') {
const cachedData = globalCache.get(item.id);
if (cachedData) {
const list = Array.isArray(cachedData) ? cachedData : (cachedData.items || []);
count = list.length;
}
}

return count === undefined || count === null ? '' : String(count);
};

