const normalizePikPakTsM3u8 = (rawText) => {
let text = String(rawText || '').replace(/\r\n/g, '\n');
if (!text.includes('#EXTM3U')) return text;

if (!text.includes('#EXT-X-ALLOW-CACHE')) {
if (text.includes('#EXT-X-MEDIA-SEQUENCE')) {
text = text.replace(
/(#EXT-X-MEDIA-SEQUENCE:[^\n]*\n)/,
'$1#EXT-X-ALLOW-CACHE:YES\n'
);
} else {
text = text.replace(
/(#EXTM3U\n)/,
'$1#EXT-X-ALLOW-CACHE:YES\n'
);
}
}

text = text.replace(
/(#EXT-X-BYTERANGE:[^\n]+)\n(#EXTINF:[^\n]+)\n/g,
'$2\n$1\n'
);

return text;
};

const getPikPakQualityRank = (name) => {
const n = String(name || '').toUpperCase();
if (n.includes('1080')) return 1080;
if (n.includes('720')) return 720;
if (n.includes('480')) return 480;
return 0;
};

const getPikPakQualityResolution = (q) => {
const width = parseInt(q.width || q.videoWidth || 0);
const height = parseInt(q.height || q.videoHeight || 0);
if (width > 0 && height > 0) return `${width}x${height}`;

const rank = getPikPakQualityRank(q.name || q.rawName);
if (rank >= 1080) return '1920x1080';
if (rank >= 720) return '1280x720';
if (rank >= 480) return '852x480';
return '1280x720';
};

const getPikPakQualityBandwidth = (q) => {
const explicit = parseInt(q.bandwidth || q.bitrate || q.bitRate || 0);
if (explicit > 0) return explicit;

const rank = getPikPakQualityRank(q.name || q.rawName);
if (rank >= 1080) return 2664403;
if (rank >= 720) return 1528012;
if (rank >= 480) return 1028110;
return 1000000;
};

const getPikPakQualityCodec = (q) => {
const codecText = String(q.codecText || '').toLowerCase();

if (
codecText.includes('avc1') ||
codecText.includes('h264') ||
codecText.includes('h.264')
) {
return 'avc1.640028,mp4a.40.2';
}

if (
q.isLikelyHevcTranscode ||
isLikelyHevcCodec(codecText) ||
codecText.includes('mpegts') ||
!codecText
) {
return 'hev1.1.6.L93.B0,mp4a.40.2';
}

return 'hev1.1.6.L93.B0,mp4a.40.2';
};

const buildPikPakMasterM3u8FromQualityList = (list) => {
const transcodes = (Array.isArray(list) ? list : [])
.filter(q => q && !q.isOriginal)
.filter(q => isPikPakTsDownloaderUrl(q.link || q.url))
.sort((a, b) => getPikPakQualityRank(b.name || b.rawName) - getPikPakQualityRank(a.name || a.rawName));

if (!transcodes.length) return '';

const lines = ['#EXTM3U'];

transcodes.forEach(q => {
const url = q.link || q.url;
const name = String(q.name || q.rawName || '').trim() || 'Auto';
const bandwidth = getPikPakQualityBandwidth(q);
const codec = getPikPakQualityCodec(q);
const resolution = getPikPakQualityResolution(q);

lines.push(`#EXT-X-STREAM-INF:BANDWIDTH=${bandwidth},CODECS="${codec}",RESOLUTION=${resolution},NAME="${name}"`);
lines.push(url);
});

return lines.join('\n') + '\n';
};

const findPikPakHlsLevelIndex = (hls, targetName, targetUrl) => {
const levels = (hls && Array.isArray(hls.levels)) ? hls.levels : [];
const wantedName = String(targetName || '').toUpperCase();
const wantedRank = getPikPakQualityRank(wantedName);

let idx = levels.findIndex(l => {
const attrs = l && l.attrs ? l.attrs : {};
const levelName = String(l.name || attrs.NAME || '').toUpperCase();
return wantedName && levelName === wantedName;
});

if (idx >= 0) return idx;

idx = levels.findIndex(l => {
const h = parseInt(l && l.height || 0);
if (!wantedRank) return false;
if (wantedRank >= 1080) return h >= 900;
if (wantedRank >= 720) return h >= 600 && h < 900;
if (wantedRank >= 480) return h > 0 && h < 600;
return false;
});

if (idx >= 0) return idx;

const wantedUrl = String(targetUrl || '');
if (wantedUrl) {
idx = levels.findIndex(l => {
const u = String((l && l.url && (Array.isArray(l.url) ? l.url[0] : l.url)) || '');
return u && wantedUrl && (u === wantedUrl || u.includes(wantedUrl) || wantedUrl.includes(u));
});
}

return idx;
};

const applyPikPakPreferredHlsLevel = (hls, targetName, targetUrl) => {
const idx = findPikPakHlsLevelIndex(hls, targetName, targetUrl);
if (idx < 0) return false;

try {
hls.currentLevel = idx;
hls.nextLevel = idx;
hls.loadLevel = idx;
return true;
} catch (e) {
console.warn('[Hls] Failed to select PikPak master level:', e);
return false;
}
};

