let sharePreviewSoftLimitSuppressed = false;
let sharePreviewStallWatch = null;
let sharePreviewStallLatched = false;
let sharePreviewStallTimer = null;
const getSharePreviewLimitTip = (it = item) => {
if (!it || !it._isShareItem) return '';
const p = it.params || {};
if (!p.anonymous_play_seconds && !p.anonymous_play_range) return '';
return L.msg_share_preview_limited_save || '';
};
const getSharePreviewExtLimitTip = (it = item) => {
if (!it || !it._isShareItem) return '';
const p = it.params || {};
if (!p.anonymous_play_seconds && !p.anonymous_play_range) return '';
return L.msg_share_ext_preview_limited_save || L.msg_share_preview_limited_save || '';
};
const getSharePreviewSoftLimitTip = () => L.msg_share_preview_soft_limit;
const hideSharePreviewSoftLimitToast = () => {
try {
const key = `warning|${normalizePkToastKeyText(getSharePreviewSoftLimitTip())}`;
document.querySelectorAll('.pk-msg-toast').forEach(n => {
if (n && n.dataset && n.dataset.pkToastKey === key) {
n.classList.add('pk-hide');
n.classList.remove('pk-show');
setTimeout(() => { try { n.remove(); } catch (e) {} }, 180);
}
});
} catch (e) {}
};
const getSharePreviewLimitParams = (it = item, duration = 0) => {
if (!it || !it._isShareItem) return null;
const p = it.params || {};
let seconds = Number(p.anonymous_play_seconds || 0);
let range = Number(p.anonymous_play_range || 0);
if (range > 1) range = range / 100;
if (!(seconds > 0) && !(range > 0)) return null;
const dur = Number(duration || (p && p.duration) || 0);
if (!(dur > 0) || !isFinite(dur)) return null;
let ratio = 0;
if (seconds > 0) ratio = Math.max(ratio, seconds / dur);
if (range > 0) ratio = Math.max(ratio, range);
ratio = Math.max(0, Math.min(1, ratio));
if (!(ratio > 0) || ratio >= 0.995) return null;
return { ratio, time: dur * ratio, seconds, range };
};

const getSharePreviewWatchNow = () => {
try { return performance.now(); } catch (e) { return Date.now(); }
};
const isSharePreviewWatchEnabled = () => !!(item && item._isShareItem);
const resetSharePreviewStallWatch = (keepLatched = false) => {
sharePreviewStallWatch = null;
if (!keepLatched) sharePreviewStallLatched = false;
};
const startSharePreviewStallWatch = (type = 'playback', targetTime = null, source = '') => {
if (!isSharePreviewWatchEnabled() || sharePreviewStallLatched) return;
const cur = Number((v && v.currentTime) || 0);
const target = Number.isFinite(Number(targetTime)) ? Number(targetTime) : cur;
if (type !== 'seek' && !(cur > 0.5 || target > 0.5)) return;
const now = getSharePreviewWatchNow();
const token = (v && v._pkMediaToken) || mediaSessionToken || 0;
if (sharePreviewStallWatch && sharePreviewStallWatch.type === 'seek' && type !== 'seek') return;
if (sharePreviewStallWatch && sharePreviewStallWatch.mediaToken === token && Math.abs((sharePreviewStallWatch.targetTime || 0) - target) < 1) return;
if (type === 'seek') {
sharePreviewSoftLimitSuppressed = true;
hideSharePreviewSoftLimitToast();
}
sharePreviewStallWatch = { type, targetTime: target, source, startedAt: now, lastProgressAt: now, lastProgressTime: cur, errorCount: 0, mediaToken: token };
};
const abortSharePreviewStallPlayback = (reason = 'stall') => {
if (!isSharePreviewWatchEnabled()) return false;
if (sharePreviewStallLatched && box.querySelector('.pk-err-dialog')) return true;
sharePreviewStallLatched = true;
sharePreviewSoftLimitSuppressed = true;
sharePreviewSoftLimitTipShown = true;
hideSharePreviewSoftLimitToast();
if (sharePreviewStallWatch) sharePreviewStallWatch.failed = true;
try { v.pause(); } catch (e) {}
try {
if (pkHls) {
pkHls.stopLoad();
pkHls.detachMedia();
pkHls.destroy();
pkHls = null;
}
} catch (e) {}
box.classList.remove('buffering');
const loader = d.querySelector('.pk-p-loading');
if (loader) loader.style.display = 'none';
const sharePreviewTip = getSharePreviewLimitTip(item);
if (sharePreviewTip && !sharePreviewLimitTipShown) {
sharePreviewLimitTipShown = true;
showToast(sharePreviewTip, 'warning', 7000);
}
console.warn('[SharePreview] Playback stalled, abort quality fallback.', {
reason,
watch: sharePreviewStallWatch,
time: v && v.currentTime,
readyState: v && v.readyState,
networkState: v && v.networkState,
currentResName,
currentLink
});
showSadBox(currentResName, 'web_unsupported', {
url: String(currentLink || ''),
name: currentResName || ''
});
return true;
};
const checkSharePreviewStallWatch = (reason = 'timer') => {
if (!isSharePreviewWatchEnabled() || !sharePreviewStallWatch || sharePreviewStallLatched) return !!sharePreviewStallLatched;
if (sharePreviewStallWatch.mediaToken && sharePreviewStallWatch.mediaToken !== mediaSessionToken) {
resetSharePreviewStallWatch();
return false;
}
const now = getSharePreviewWatchNow();
const cur = Number((v && v.currentTime) || 0);
const epsilon = Math.max(0.2, Number(CONF.sharePreviewStallProgressEpsilon) || 0.8);
const moved = Math.abs(cur - Number(sharePreviewStallWatch.lastProgressTime || 0)) >= epsilon;
if (moved && v && v.readyState >= 2) {
resetSharePreviewStallWatch();
return false;
}
const timeout = sharePreviewStallWatch.type === 'seek'
? Math.max(3000, Number(CONF.sharePreviewSeekStallTimeoutMs) || 10000)
: Math.max(5000, Number(CONF.sharePreviewPlaybackStallTimeoutMs) || 12000);
const elapsed = now - Number(sharePreviewStallWatch.startedAt || now);
const errorLimit = Math.max(1, Number(CONF.sharePreviewStallErrorLimit) || 3);
const stuckByTime = elapsed >= timeout && !moved;
const stuckByError = Number(sharePreviewStallWatch.errorCount || 0) >= errorLimit && !moved;
if (!stuckByTime && !stuckByError) return false;
return abortSharePreviewStallPlayback(reason);
};
const markSharePreviewStallError = (err = {}) => {
if (!isSharePreviewWatchEnabled() || sharePreviewStallLatched) return !!sharePreviewStallLatched;
if (!sharePreviewStallWatch) {
if (!box || !box.classList.contains('buffering')) return false;
startSharePreviewStallWatch('playback', Number((v && v.currentTime) || 0), 'error');
}
if (!sharePreviewStallWatch) return false;
sharePreviewStallWatch.errorCount = Number(sharePreviewStallWatch.errorCount || 0) + 1;
console.warn('[SharePreview] Stall watch error.', {
count: sharePreviewStallWatch.errorCount,
limit: Math.max(1, Number(CONF.sharePreviewStallErrorLimit) || 3),
type: sharePreviewStallWatch.type,
time: v && v.currentTime,
readyState: v && v.readyState,
networkState: v && v.networkState,
errCode: v && v.error ? v.error.code : (err && err.force ? 4 : 0),
currentResName,
currentLink
});
return checkSharePreviewStallWatch('error');
};
const markSharePreviewPlaybackProgress = () => {
if (!isSharePreviewWatchEnabled() || !v) return;
const cur = Number(v.currentTime || 0);
if (!(cur > 0)) return;
if (!sharePreviewStallWatch) return;
const epsilon = Math.max(0.2, Number(CONF.sharePreviewStallProgressEpsilon) || 0.8);
if (Math.abs(cur - Number(sharePreviewStallWatch.lastProgressTime || 0)) >= epsilon && v.readyState >= 2) {
console.warn('[SharePreview] Stall watch recovered.', {
type: sharePreviewStallWatch.type,
time: cur,
watch: sharePreviewStallWatch
});
sharePreviewSoftLimitSuppressed = false;
resetSharePreviewStallWatch();
}
};

const isVideoItem = (it) => {
if (!it || it.isHeader || it.kind === 'drive#folder') return false;
if (S.offlineMode && it.phase !== 'PHASE_TYPE_COMPLETE') return false;
if (S.uploadMode && it.status !== 'DONE') return false;
const m = (it.mime_type || '').toLowerCase();
const n = (it.name || '').toLowerCase();
const dur = (it.params && it.params.duration) || 0;
const vExts = ['mp4','mkv','avi','mov','wmv','flv','webm','ts','m4v','3gp'];
return m.startsWith('video/') || dur > 0 || vExts.some(e => n.endsWith('.' + e));
};

const videoPlaylist = S.display.filter(i => isVideoItem(i));
let curListIdx = videoPlaylist.findIndex(v => v.id === item.id);
const totalInList = videoPlaylist.length;
let isSwitching = false;
let switchReqId = 0;
let mediaSessionToken = 0;
let activeHealthTimer = null;
let activeHlsObjectUrl = null;
const isStaleMediaSession = (token) => token !== mediaSessionToken || isPlayerDestroyed;
const showSadBox = (codecName, reason = 'codec', opts = {}) => {
if (box.querySelector('.pk-err-dialog')) return;
if (posterEl) {
posterEl.style.transition = 'none';
posterEl.style.display = 'flex';
posterEl.style.opacity = '1';
posterEl.style.pointerEvents = 'auto';
}

const savedPlayer = gmGet('pk_ext_player', 'potplayer');
const sadBoxSVG = `<svg width="85" height="85" viewBox="0 0 100 100" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M20 45l15-15h30l15 15H20z" fill="#777"/><path d="M20 45L5 30h20l15 15H20z" fill="#999"/><path d="M80 45l15-15H75L60 45h20z" fill="#999"/><path fill-rule="evenodd" d="M20 45h60v35c0 5-5 5-5 5H25c-5 0-5-5-5-5V45zm16.5 14c0 3.3 1.5 6 3.5 6s3.5-2.7 3.5-6-1.5-6-3.5-6-3.5 2.7-3.5 6zm20 0c0 3.3 1.5 6 3.5 6s3.5-2.7 3.5-6-1.5-6-3.5-6-3.5 2.7-3.5 6z" fill="#aaa"/><path d="M38 16a12 8 0 1 0 24 0a12 8 0 1 0-24 0M48 24l2 3.5l2-3.5h-4z" fill="#aaa"/><path d="M47 13l6 6M53 13l-6 6" stroke="#181818" stroke-width="1.8" stroke-linecap="round"/></svg>`;
const isWebUnsupportedHint = reason === 'web_unsupported';
const safeQualityList = Array.isArray(qualityList) ? qualityList : [];
const preferredErrUrl = String(opts.url || currentLink || '');
const preferredErrName = String(opts.name || currentResName || codecName || '');
const fallbackQuality = safeQualityList[0] || { name: preferredErrName, link: preferredErrUrl, url: preferredErrUrl };
const recommended = isWebUnsupportedHint ? (safeQualityList.find(q => String(q.link || q.url || '') === preferredErrUrl) || safeQualityList.find(q => String(q.name || '') === preferredErrName) || safeQualityList.find(q => String(q.name || '') === String(currentResName || '')) || fallbackQuality) : (safeQualityList.find(q => !q.isOriginal) || fallbackQuality);
const recommendedUrl = preferredErrUrl || recommended.link || recommended.url;
let selectedErrUrl = recommendedUrl;
let selectedErrName = preferredErrName || recommended.name;
let selectedErrPlayer = (savedPlayer === 'other') ? 'other' : 'potplayer';
const resOptions = safeQualityList.map(q => {
const qUrl = q.link || q.url;
const isSelected = qUrl === selectedErrUrl;
return `<div class="pk-select-item ${isSelected ? 'act' : ''}" data-val="${qUrl}">${q.name}</div>`;
}).join('');
const lblRes = L.lbl_resolution;
const errTitle = isWebUnsupportedHint ? L.err_web_unsupported_t1 : L.err_codec_t1.replace('{c}', codecName);
const errDesc = isWebUnsupportedHint ? L.err_web_unsupported_t2 : L.err_codec_t2;
const shareExtPreviewTip = getSharePreviewExtLimitTip(item);
const dialog = document.createElement('div');
dialog.className = 'pk-err-dialog';
dialog.style.cssText = "position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);background:rgba(30, 30, 30, 0.85);backdrop-filter:blur(12px);border-radius:12px;padding:40px 50px;display:flex;flex-direction:column;align-items:center;text-align:center;box-shadow:0 20px 60px rgba(0,0,0,0.8);z-index:999;min-width:400px;border:1px solid rgba(255,255,255,0.1);";
dialog.innerHTML = `
<div class="pk-err-close" style="position:absolute;top:15px;right:15px;cursor:pointer;color:#fff;padding:5px;display:flex;align-items:center;justify-content:center;opacity:0.7;transition:opacity 0.2s;" onmouseover="this.style.opacity=1" onmouseout="this.style.opacity=0.7"><svg viewBox="0 0 24 24" width="18" height="18" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M18 6L6 18M6 6l12 12"/></svg></div>
<div style="margin-bottom:20px;">${sadBoxSVG}</div>
<div style="font-size:16px;font-weight:bold;color:#fff;margin-bottom:10px;max-width:400px;line-height:1.4;">${errTitle}</div>
<div style="font-size:12px;color:#999;margin-bottom:30px;">${errDesc}</div>
${shareExtPreviewTip ? `<div style="width:100%;box-sizing:border-box;font-size:12px;line-height:1.6;color:#f5c26b;background:rgba(245,194,107,.1);border:1px solid rgba(245,194,107,.22);border-radius:8px;padding:9px 11px;margin:-12px 0 22px;text-align:left;">${shareExtPreviewTip}</div>` : ''}

<div style="display:flex;flex-direction:column;gap:25px;width:100%;margin-bottom:25px;text-align:left;">
<fieldset class="pk-custom-select pk-err-field-select" id="pk_err_res_cs" style="width:100%;z-index:20;">
<legend class="pk-select-label">${lblRes}</legend>
<div class="pk-select-trigger">
    <span id="txt_err_res">${selectedErrName}</span>
    <div style="display:flex;color:#999;">${CONF.crumbIcons.down}</div>
</div>
<div class="pk-select-menu pk-scroll">
    ${resOptions}
</div>
</fieldset>

<fieldset class="pk-custom-select pk-err-field-select" id="pk_err_player_cs" style="width:100%;z-index:10;">
<legend class="pk-select-label">${L.lbl_player}</legend>
<div class="pk-select-trigger">
    <span id="txt_err_player">${selectedErrPlayer === 'potplayer' ? 'PotPlayer' : L.opt_player_other}</span>
    <div style="display:flex;color:#999;">${CONF.crumbIcons.down}</div>
</div>
<div class="pk-select-menu">
    <div class="pk-select-item ${selectedErrPlayer === 'potplayer' ? 'act' : ''}" data-val="potplayer">PotPlayer</div>
    <div class="pk-select-item ${selectedErrPlayer === 'other' ? 'act' : ''}" data-val="other">${L.opt_player_other}</div>
</div>
</fieldset>
<button type="button" class="pk-potfix-entry" id="pk_err_potplayer_fix" style="align-self:flex-start;color:#4cc2ff;margin-top:-14px;${selectedErrPlayer === 'potplayer' ? '' : 'display:none;'}">${L.potplayer_fix_entry}</button>
</div>
<button id="pk_err_launch_btn" style="background:#fff;color:#000;border:none;padding:10px 40px;border-radius:6px;font-size:14px;font-weight:bold;cursor:pointer;transition:background 0.2s;">${L.btn_start_play}</button>
`;

box.appendChild(dialog);

const launchBtn = dialog.querySelector('#pk_err_launch_btn');
const fixBtn = dialog.querySelector('#pk_err_potplayer_fix');

const closeErrMenus = () => {
dialog.querySelectorAll('.pk-select-menu').forEach(menu => menu.style.display = 'none');
dialog.querySelectorAll('.pk-custom-select').forEach(cs => cs.classList.remove('pk-select-open'));
};
const removeErrDialog = () => {
document.removeEventListener('click', closeErrMenus);
dialog.remove();
};
const getCleanErrSelectedUrl = () => {
let cleanLink = String(selectedErrUrl || '').replace('&ext=.m3u8', '');
if (cleanLink.includes('ts_downloader') && cleanLink.includes('url=')) {
try {
const urlParam = new URL(cleanLink).searchParams.get('url');
if (urlParam) cleanLink = decodeURIComponent(urlParam);
} catch (e) {}
}
return rewriteDownloadLinkForAccel(cleanLink, 'external');
};
const updateErrPotPlayerFixEntry = () => {
if (fixBtn) fixBtn.style.display = selectedErrPlayer === 'potplayer' ? 'inline-flex' : 'none';
};
const bindErrSelect = (id, onSelect) => {
const container = dialog.querySelector(`#${id}`);
if (!container) return;
const trigger = container.querySelector('.pk-select-trigger');
const menu = container.querySelector('.pk-select-menu');
const txt = container.querySelector('.pk-select-trigger > span');
if (!trigger || !menu || !txt) return;

trigger.onclick = (e) => {
e.stopPropagation();
const isOpen = menu.style.display === 'block';
closeErrMenus();
menu.style.display = isOpen ? 'none' : 'block';
container.classList.toggle('pk-select-open', !isOpen);
};

container.querySelectorAll('.pk-select-item').forEach(item => {
item.onclick = (e) => {
e.stopPropagation();
container.querySelectorAll('.pk-select-item').forEach(i => i.classList.remove('act'));
item.classList.add('act');
txt.textContent = item.textContent;
menu.style.display = 'none';
container.classList.remove('pk-select-open');
onSelect(item.dataset.val, item.textContent);
};
});
};

dialog.querySelector('.pk-err-close').onclick = (e) => {
e.stopPropagation();
removeErrDialog();
};

dialog.onclick = (e) => e.stopPropagation();

bindErrSelect('pk_err_res_cs', (val, text) => {
selectedErrUrl = val;
selectedErrName = text;
});

bindErrSelect('pk_err_player_cs', (val) => {
selectedErrPlayer = val;
launchBtn.textContent = (val === 'other') ? L.btn_copy_link : L.btn_start_play;
updateErrPotPlayerFixEntry();
});

launchBtn.textContent = (selectedErrPlayer === 'other') ? L.btn_copy_link : L.btn_start_play;
setTimeout(() => document.addEventListener('click', closeErrMenus), 0);

if (fixBtn) {
fixBtn.onclick = (e) => {
e.preventDefault();
e.stopPropagation();
openPotPlayerProtocolRepairHelper(getCleanErrSelectedUrl(), {
button: launchBtn,
source: 'error_fallback',
onRetryLikelyOpen: () => {
    removeErrDialog();
    destroyPlayer();
},
onRetryLikelyFail: () => {
    removeErrDialog();
    destroyPlayer();
}
});
};
}

launchBtn.onclick = (e) => {
e.stopPropagation();
const selPlayer = selectedErrPlayer;
const selResName = selectedErrName;

gmSet('pk_ext_player', selPlayer);

const cleanLink = getCleanErrSelectedUrl();

if (selPlayer === 'other') {
GM_setClipboard(cleanLink);
launchBtn.textContent = L.msg_copy_success;
launchBtn.style.background = "#52c41a";
launchBtn.style.color = "#fff";
setTimeout(() => {
removeErrDialog();
if (typeof destroyPlayer === 'function') destroyPlayer();
}, 800);
}
else if (selPlayer === 'potplayer') {
launchPotPlayerWithFallback(cleanLink, {
button: launchBtn,
source: 'error_fallback',
restoreText: L.btn_start_play,
restoreBg: launchBtn.style.background,
restoreColor: launchBtn.style.color,
failToastDuration: 6500,
failCloseDelay: 3200,
onLikelyOpen: () => {
    removeErrDialog();
    destroyPlayer();
},
onLikelyFail: (ctx) => {
    removeErrDialog();
    destroyPlayer();
    schedulePotPlayerAutoRepairPrompt(cleanLink, {
        source: 'error_fallback',
        autoRepairPrompt: ctx && ctx.autoRepairPrompt,
        autoRepairPromptDelay: ctx && ctx.autoRepairPromptDelay
    });
}
});
}
else {
const curT = v.currentTime;
currentLink = selResLink;
currentResName = selResName;

box.classList.add('buffering');
if (posterEl) {
if (v.readyState >= 2 && v.currentTime > 0) {
    try {
        const cvs = document.createElement('canvas');
        cvs.width = v.videoWidth; cvs.height = v.videoHeight;
        cvs.getContext('2d').drawImage(v, 0, 0);
        posterEl.querySelector('img').src = cvs.toDataURL('image/jpeg', 0.7);
    } catch (err) {}
}
posterEl.style.display = 'flex';
posterEl.style.opacity = '1';
}

if(resTxt) resTxt.textContent = currentResName;
if(resList) {
resList.innerHTML = renderQualityMenu(qualityList, currentResName);
bindResEvents();
}

removeErrDialog();
shutterTargetTime = curT > 0.1 ? curT : 0;
loadSource(currentLink, curT);
v.play().catch(()=>{});
}
};
};

const renderPlaylistItems = () => {
const RANGE = 150;
const start = Math.max(0, curListIdx - RANGE);
const end = Math.min(videoPlaylist.length, curListIdx + RANGE + 1);

return videoPlaylist.slice(start, end).map((v, i) => {
const absIdx = start + i;
const coverSrc = (v.thumbnail_link && v.thumbnail_link !== v.icon_link) ? v.thumbnail_link : '';
const phSrc = v.icon_link || v.thumbnail_link || '';
const phSvg = getIcon(v);
return `
<div class="pk-p-plist-item ${absIdx === curListIdx ? 'active' : ''}"
data-idx="${absIdx}"
data-name="${esc(v.name)}"
data-size="${fmtSize(v.size)}">
<div class="pk-p-plist-ph">
${phSrc ? `<img src="${phSrc}" draggable="false">` : phSvg}
</div>
${coverSrc ? `<img src="${coverSrc}" style="filter:none !important;opacity:0;" draggable="false" onload="this.style.opacity='1';if(this.previousElementSibling)this.previousElementSibling.style.display='none';" onerror="this.remove();if(this.previousElementSibling)this.previousElementSibling.style.display='flex';" loading="lazy">` : ``}
</div>
`;
}).join('');
};

const triggerResume = (targetVideo, targetItem) => {
if (!shouldLoadVideoProgressCache()) return;
if (targetVideo._hasShownResumeToast || hasUserSeeked || targetVideo._isRestarting) return;

const targetId = getPhysicalId(targetItem);
if (targetVideo._pkActiveFileId && targetVideo._pkActiveFileId !== targetId) return;
if (targetVideo._pkOfficialResumeFileId && targetVideo._pkOfficialResumeFileId !== targetId) return;

const savedT = parseFloat(targetVideo._pkOfficialResumeTime || 0);
const skipOp = targetVideo._pkIntroSkipApplied ? (parseInt(gmGet('pk_skip_intro', 0)) || 0) : 0;

if (savedT > 5 || skipOp > 0) {
targetVideo._hasShownResumeToast = true;
} else {
return;
}

const showToast = (text) => {
const oldToast = d.querySelector('.pk-p-resume-toast');
if (oldToast) oldToast.remove();
const toast = document.createElement('div');
toast.className = 'pk-p-resume-toast';
toast.style.zIndex = "150";
toast.innerHTML = `<span>${text}</span><span class="pk-p-resume-btn" id="pk_re_start">${L.btn_restart}</span><div class="pk-p-resume-close" id="pk_re_close">${mkSvg(icons.close)}</div>`;
d.querySelector('#pk_p_box').appendChild(toast);

toast.querySelector('#pk_re_start').onclick = (e) => {
e.stopPropagation();
if (tCur) tCur.textContent = "00:00:00";
if (progFilled) progFilled.style.setProperty('width', '0%', 'important');
shutterTargetTime = 0.1;
targetVideo._isRestarting = true;
targetVideo.currentTime = 0;
toast.remove();
};
toast.querySelector('#pk_re_close').onclick = (e) => { e.stopPropagation(); toast.remove(); };
setTimeout(() => { if(toast.parentNode) toast.remove(); }, 8000);
};

if (savedT > 5) {
showToast(L.msg_resume_hint.replace('{t}', fmtT(savedT)));
} else if (skipOp > 0) {
const dp = d.querySelector('.pk-player-box');
if(dp && !dp.querySelector('.pk-skip-toast')) {
const tip = document.createElement('div');
tip.className = 'pk-skip-toast';
tip.style.cssText = "position:absolute;top:80px;left:20px;background:rgba(0,0,0,0.6);color:#ddd;padding:4px 8px;border-radius:4px;font-size:12px;pointer-events:none;animation:pkFadeIn 0.5s;";
tip.textContent = `${L.lbl_skip_op} ${skipOp}s`;
dp.appendChild(tip);
setTimeout(()=>tip.remove(), 3000);
}
}
};

const softSwitch = async (newIdx, scrollMode = 'smooth') => {
if (!videoPlaylist[newIdx]) return;

switchReqId++;
mediaSessionToken++;
const myReqId = switchReqId;
isSwitching = true;
lastWorkingLink = null;
lastWorkingResName = null;
failedUrls.clear();
resetSharePreviewStallWatch();
const v = d.querySelector('#pk_video');
const loader = d.querySelector('.pk-p-loading');
const poster = d.querySelector('#pk_p_poster');
if (shouldSyncOfficialPlayHistory(item) && v && v.currentTime > 5 && v.duration > 0 && v.duration - v.currentTime > 5) {
if (!officialProgressPostedThisSession && !officialProgressPosting) {
    officialProgressPosting = true;
    postOfficialPlayProgress(getPhysicalId(item), v.currentTime, v.duration)
        .then(handleOfficialPlayProgressWriteResult)
        .catch(() => {})
        .finally(() => { officialProgressPosting = false; });
}
}

if (activeHealthTimer) {
clearInterval(activeHealthTimer);
activeHealthTimer = null;
}

if (pkHls) {
try { pkHls.stopLoad(); } catch (e) {}
try { pkHls.detachMedia(); } catch (e) {}
try { pkHls.destroy(); } catch (e) {}
pkHls = null;
}

if (activeHlsObjectUrl) {
try { URL.revokeObjectURL(activeHlsObjectUrl); } catch (e) {}
activeHlsObjectUrl = null;
}

if (v) {
v.pause();
v._bufferingSince = null;
v._blackScreenCount = 0;
v._isRestarting = false;
v._hasShownResumeToast = false;
v._pkPendingIntroSkip = 0;
v._pkIntroSkipApplied = false;
Array.from(v.querySelectorAll('track')).forEach(t => t.remove());

if (subState.blobUrl) {
URL.revokeObjectURL(subState.blobUrl);
subState.blobUrl = null;
}
subState.hasSub = false;
subState.track = null;

const subNameLabel = d.querySelector('#pk_sub_name');
if (subNameLabel) subNameLabel.textContent = L.str_no_sub;

v.src = "";
v.load();
}

if (progFilled) progFilled.style.setProperty('width', '0%', 'important');
sharePreviewSoftLimitTipShown = false;
sharePreviewSoftLimitSuppressed = false;
if (sharePreviewLimitMarker) sharePreviewLimitMarker.style.display = 'none';
const newItem = videoPlaylist[newIdx];
if (tCur) tCur.textContent = '00:00:00';
if (tDur) {
const newPId = getPhysicalId(newItem);
const knownDur = (newItem.params && newItem.params.duration) ||
            S.durationMap.get(newPId) ||
            gmGet('pk_duration_' + newPId, 0);
tDur.textContent = knownDur > 0 ? fmtT(knownDur) : '00:00:00';
}

transformState = { rotate: 0, flipH: 1, flipV: 1, ratio: 'default' };
if (typeof applyTransform === 'function') applyTransform();

const ratioBtns = d.querySelectorAll('#pk_ratio_opts .pk-size-btn');
ratioBtns.forEach(btn => {
if (btn.dataset.ratio === 'default') btn.classList.add('active');
else btn.classList.remove('active');
});

if (loader) loader.style.display = 'block';
box.classList.add('buffering');
hasCheckedProgress = false;
const oldResumeToast = d.querySelector('.pk-p-resume-toast');
if (oldResumeToast) oldResumeToast.remove();
const errDialogs = d.querySelectorAll('.pk-err-dialog');
errDialogs.forEach(el => el.remove());
const linkOvs = d.querySelectorAll('.pk-link-export-ov');
linkOvs.forEach(el => el.remove());
const searchModal = d.querySelector('.pk-sub-search-modal');
if (searchModal) searchModal.remove();
const btnSearchS = d.querySelector('#pk_p_search');
if (btnSearchS) btnSearchS.style.setProperty('display', 'none', 'important');
const btnPipS = d.querySelector('#pk_p_pip');
if (btnPipS) btnPipS.style.setProperty('display', 'none', 'important');

curListIdx = newIdx;
item = newItem;

if (posterEl) {
posterEl.style.transition = 'none';
posterEl.style.display = 'flex';
posterEl.style.opacity = '1';

const img = posterEl.querySelector('img');
if (img && newItem.thumbnail_link) {
img.style.display = 'block';
img.src = newItem.thumbnail_link.replace('SIZE_MEDIUM', 'SIZE_LARGE');
img.style.opacity = '0';
img.onload = () => {
img.style.opacity = '1';
if (btnSearchS) btnSearchS.style.setProperty('display', 'flex', 'important');
};
img.onerror = () => img.style.display = 'none';
} else if (img) {
img.style.display = 'none';
}

setTimeout(() => { posterEl.style.transition = 'opacity 0.4s ease'; }, 50);
}

if (loaderEl) loaderEl.style.display = 'block';

const pTitle = d.querySelector('.pk-player-title');
if(pTitle) pTitle.textContent = `[${newIdx + 1}/${totalInList}] ${newItem.name}`;
const pTab = d.querySelector('#pk_p_plist_tab');
if(pTab) pTab.innerHTML = `${curListIdx + 1} / ${totalInList} <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><polyline points="18 15 12 9 6 15"></polyline></svg>`;

if (pScroll) {
syncVideoPlistItems(
scrollMode === 'instant'
? 'instant'
: (box.classList.contains('plist-active') ? 'smooth' : false)
);
}

const btnL = d.querySelector('#pk_p_side_L');
const btnR = d.querySelector('#pk_p_side_R');
if (btnL) btnL.style.display = newIdx === 0 ? 'none' : 'flex';
if (btnR) btnR.style.display = newIdx === totalInList - 1 ? 'none' : 'flex';

if (typeof updatePlistNav === 'function') updatePlistNav();

hasUserSeeked = false;

try {
const targetApiId = getPhysicalId(newItem);
const newData = newItem._isShareItem ? await resolveSharePlayableFile(newItem) : await apiGet(targetApiId);
if (newData) {
if (newData.thumbnail_link) newItem.thumbnail_link = newData.thumbnail_link;
if (newData.icon_link) newItem.icon_link = newData.icon_link;
}

if (myReqId !== switchReqId) return;
const freshData = getBestSource(newData);
currentResName = freshData.name;
currentLink = freshData.src;
qualityList = freshData.list;
const resTxt = d.querySelector('#pk_p_res_txt');
if (resTxt) resTxt.textContent = currentResName;
const resList = d.querySelector('#pk_p_res_list');
if (resList) {
resList.innerHTML = renderQualityMenu(qualityList, currentResName);
bindResEvents();
}
loadSource(freshData.src, null);
if (typeof ThumbnailEngine !== 'undefined') {
ThumbnailEngine.resetSource(freshData.src);
}
if(poster) poster.style.display = 'block';
if (d.querySelector('#pk_sub_name')) d.querySelector('#pk_sub_name').textContent = L.str_no_sub;
autoMatchSubtitle(newItem);

if (!isPlayerDestroyed) {
await v.play().catch(()=>{});
}

if (!v.paused && !isPlayerDestroyed) {
box.classList.add('pk-v-started');
stopSpinner();
}
updateState();

} catch (err) {
await markOfflineReferenceMissingFromError(newItem, err, { source: 'video_switch' });
if (myReqId === switchReqId) console.error("[SoftSwitch] Critical Error:", err);
} finally {
if (myReqId === switchReqId) {
isSwitching = false;
if (loader && (v.readyState >= 2 || box.querySelector('.pk-err-dialog'))) loader.style.display = 'none';
}
}
};

const getLoadedHistoryProgress = (it) => {
if (!shouldLoadVideoProgressCache() || !S.historyMode || !it) return null;

const targetId = String(getPhysicalId(it) || '');
if (!targetId) return null;

const candidates = [it];
const mapItem = S.itemMap && S.itemMap.get(targetId);
if (mapItem) candidates.push(mapItem);

if (Array.isArray(S.items)) {
const itemInList = S.items.find(f => f && String(f.id || '') === targetId);
if (itemInList) candidates.push(itemInList);
}

if (Array.isArray(S.display)) {
const itemInDisplay = S.display.find(f => f && !f.isHeader && String(f.id || '') === targetId);
if (itemInDisplay) candidates.push(itemInDisplay);
}

for (const h of candidates) {
const t = parseOfficialPlaySeconds(h && h._history_progress);
const d = parseOfficialPlaySeconds((h && h._history_duration) || (h && h.params && h.params.duration) || S.durationMap.get(targetId) || gmGet('pk_duration_' + targetId, 0));
if (t > 5 && !(d > 0 && d - t <= 5)) {
return {
t,
d,
ts: Number((h && h._history_ts) || 0),
source: 'loaded_history',
officialEventId: String((h && h._history_event_id) || '')
};
}
}

return null;
};

const loadSource = async (url, customStartTime = null) => {
sharePreviewSoftLimitTipShown = false;
if (sharePreviewLimitMarker) sharePreviewLimitMarker.style.display = 'none';
let startTime = 0;
const skipOp = parseInt(gmGet('pk_skip_intro', 0)) || 0;
const pId = getPhysicalId(item);
let shouldPendingIntroSkip = false;

v._pkActiveFileId = pId;
v._pkOfficialResumeTime = 0;
v._pkOfficialResumeFileId = '';
v._hasShownResumeToast = false;
const oldResumeToast = d.querySelector('.pk-p-resume-toast');
if (oldResumeToast) oldResumeToast.remove();

let loadedHistoryProgress = null;

if (customStartTime !== null) {
startTime = customStartTime;
} else {
loadedHistoryProgress = getLoadedHistoryProgress(item);
if (loadedHistoryProgress) {
startTime = loadedHistoryProgress.t;
v._pkOfficialResumeTime = startTime;
v._pkOfficialResumeFileId = pId;
} else if (skipOp > 0) {
const knownDur = (item.params && item.params.duration) || S.durationMap.get(pId) || gmGet('pk_duration_' + pId, 0);
if (knownDur > 0 && skipOp >= knownDur) {
console.warn(`[AutoSkip] Intro skip (${skipOp}s) exceeds total duration (${knownDur}s), ignored.`);
} else {
shouldPendingIntroSkip = true;
}
}
}

v._pkPendingIntroSkip = shouldPendingIntroSkip ? skipOp : 0;
v._pkIntroSkipApplied = false;

shutterTargetTime = startTime > 1 ? startTime : 0;
if (tCur) tCur.textContent = fmtT(startTime);
const totalDur = (item.params && item.params.duration) ||
        S.durationMap.get(pId) ||
        gmGet('pk_duration_' + pId, 0);

if (progFilled && totalDur > 0) {
const pct = Math.min(100, (startTime / totalDur) * 100);
progFilled.style.setProperty('width', `${pct}%`, 'important');
}

const currentMediaToken = ++mediaSessionToken;

if (customStartTime === null && !loadedHistoryProgress && shouldSyncOfficialPlayHistory(item) && shouldLoadVideoProgressCache()) {
fetchOfficialPlayHistoryProgress(pId).then((officialProgress) => {
if (!officialProgress || isStaleMediaSession(currentMediaToken) || hasUserSeeked || v._isRestarting) return;
if (v._pkActiveFileId !== pId || getPhysicalId(item) !== pId) return;

const officialT = parseFloat(officialProgress.t || 0);
const officialD = parseFloat(officialProgress.d || 0);
if (!(officialT > 5)) return;
if (officialD > 0 && officialD - officialT <= 5) return;

const currentT = parseFloat(v.currentTime || 0);
if (currentT > 5 && Math.abs(currentT - startTime) > 5) return;

const applyOfficialProgress = () => {
if (isStaleMediaSession(currentMediaToken) || hasUserSeeked || v._isRestarting) return;
if (v._pkActiveFileId !== pId || getPhysicalId(item) !== pId) return;

shutterTargetTime = officialT > 1 ? officialT : 0;

try {
    v.currentTime = officialT;
} catch (e) {
    console.warn('[OfficialProgress] Seek failed:', e);
}

if (tCur) tCur.textContent = fmtT(officialT);

const knownDur = officialD ||
                    (item.params && item.params.duration) ||
                    S.durationMap.get(pId) ||
                    gmGet('pk_duration_' + pId, 0);

if (progFilled && knownDur > 0) {
    const pct = Math.min(100, (officialT / knownDur) * 100);
    progFilled.style.setProperty('width', `${pct}%`, 'important');
}

v._pkOfficialResumeTime = officialT;
v._pkOfficialResumeFileId = pId;
v._hasShownResumeToast = false;
triggerResume(v, item);
};

if (v.readyState >= 1) {
applyOfficialProgress();
} else {
v.addEventListener('loadedmetadata', applyOfficialProgress, { once: true });
}
}).catch((e) => {
console.warn('[OfficialProgress] Apply failed:', e);
});
}

if (activeHealthTimer) {
clearInterval(activeHealthTimer);
activeHealthTimer = null;
}

if (pkHls) {
try { pkHls.stopLoad(); } catch (e) {}
try { pkHls.detachMedia(); } catch (e) {}
try { pkHls.destroy(); } catch (e) {}
pkHls = null;
}

if (activeHlsObjectUrl) {
try { URL.revokeObjectURL(activeHlsObjectUrl); } catch (e) {}
activeHlsObjectUrl = null;
}

v._pkMediaToken = currentMediaToken;
v._bufferingSince = null;
v._blackScreenCount = 0;
box.classList.add('buffering');

const isPikPakTsHls = isPikPakTsDownloaderUrl(url);
const isM3u8 = url.includes('.m3u8') || isPikPakTsHls;
const currentQualityItem = (Array.isArray(qualityList) ? qualityList : []).find(q => {
const qUrl = String(q && (q.link || q.url) || '');
return qUrl && (qUrl === url || qUrl === currentLink || String(q.name || '') === String(currentResName || ''));
}) || null;

if (currentQualityItem && shouldBlockWebPlaybackByOfficialSniff(currentQualityItem)) {
console.warn('[VideoCheck] Web playback blocked by official-like codec sniff.', {
name: currentQualityItem.name || currentResName,
codecText: getPikPakQualityCodecTextForSniff(currentQualityItem),
hevcWebSupport: hasLikelyHevcWebPlaybackSupport()
});

box.classList.remove('buffering');
const loader = d.querySelector('.pk-p-loading');
if (loader) loader.style.display = 'none';

showSadBox(currentQualityItem.codecText || 'HEVC', 'web_unsupported', {
url: String((currentQualityItem.link || currentQualityItem.url) || url || currentLink || ''),
name: currentQualityItem.name || currentResName
});
return;
}

const HlsCtor = isPikPakTsHls
? (getPikPakOfficialHlsCtor() || window.Hls)
: window.Hls;

const usingOfficialPikPakHls = isPikPakTsHls && HlsCtor && HlsCtor !== window.Hls;
const HlsEvents = (HlsCtor && HlsCtor.Events) || (window.Hls && window.Hls.Events) || {};
const HlsErrorTypes = (HlsCtor && HlsCtor.ErrorTypes) || (window.Hls && window.Hls.ErrorTypes) || {};

if (isM3u8 && HlsCtor && HlsCtor.isSupported && HlsCtor.isSupported()) {
let finalPlayUrl = url;

if (url.includes('&ext=.m3u8') || url.includes('?ext=.m3u8')) {
finalPlayUrl = buildPikPakTsHlsUrl(url);
}

let isOfficialPikPakTsHls = isPikPakTsDownloaderUrl(finalPlayUrl);
let pikPakMasterTargetName = '';
let pikPakMasterTargetUrl = '';
const hlsLoadStartedAt = Date.now();

if (isOfficialPikPakTsHls) {
const targetItem = (Array.isArray(qualityList) ? qualityList : []).find(q => {
const qUrl = String(q.link || q.url || '');
return qUrl && (qUrl === finalPlayUrl || q.name === currentResName);
});

pikPakMasterTargetName = (targetItem && targetItem.name) || currentResName || '';
pikPakMasterTargetUrl = (targetItem && (targetItem.link || targetItem.url)) || finalPlayUrl;

const masterM3u8 = buildPikPakMasterM3u8FromQualityList(qualityList);

if (masterM3u8) {
const blob = new Blob([masterM3u8], {
    type: 'audio/mpegurl'
});

finalPlayUrl = URL.createObjectURL(blob);
activeHlsObjectUrl = finalPlayUrl;

} else {
try {
    const manifestRes = await fetch(finalPlayUrl, {
        method: 'GET',
        cache: 'no-store',
        credentials: 'omit'
    });

    if (isStaleMediaSession(currentMediaToken)) return;

    if (manifestRes && manifestRes.ok) {
        const rawManifest = await manifestRes.text();
        const fixedManifest = normalizePikPakTsM3u8(rawManifest);

        if (fixedManifest.includes('#EXTM3U')) {
            const blob = new Blob([fixedManifest], {
                type: 'application/vnd.apple.mpegurl'
            });

            finalPlayUrl = URL.createObjectURL(blob);
            activeHlsObjectUrl = finalPlayUrl;
        }
    } else {
        console.warn("[Hls] Failed to prefetch PikPak ts_downloader manifest, fallback to direct HLS URL:", manifestRes && manifestRes.status);
    }
} catch (e) {
    console.warn("[Hls] Prefetch PikPak ts_downloader manifest failed, fallback to direct HLS URL:", e);
}
}
}

const hlsOptions = usingOfficialPikPakHls ? {
debug: false,
maxBufferHole: 0.5,
maxFragLookUpTolerance: 0.2,
enableWorker: true,
progressive: true,
abrBandWidthFactor: 0,
abrBandWidthUpFactor: 0,
maxMaxBufferLength: 30,
maxBufferLength: 10,
maxBufferSize: 60 * 1024 * 1024,
fragLoadPolicy: {
default: {
    maxTimeToFirstByteMs: 10000,
    maxLoadTimeMs: 15000,
    timeoutRetry: {
        maxNumRetry: 6,
        retryDelayMs: 1000,
        maxRetryDelayMs: 0
    },
    errorRetry: {
        maxNumRetry: 2,
        retryDelayMs: 1000,
        maxRetryDelayMs: 8000
    }
}
},
lowLatencyMode: false,
backBufferLength: 30,
forceKeyFrameOnDiscontinuity: true,
startPosition: startTime,
startLevel: -1,
capLevelToPlayerSize: false
} : {
debug: false,
enableWorker: true,
lowLatencyMode: false,
startPosition: startTime,
fragLoadingMaxRetry: 3,
manifestLoadingMaxRetry: 3,
levelLoadingMaxRetry: 3,
fragLoadingRetryDelay: 800,
manifestLoadingRetryDelay: 800,
levelLoadingRetryDelay: 800,
fragLoadingTimeOut: 20000,
manifestLoadingTimeOut: 15000,
maxBufferHole: 0.8,
maxFragLookUpTolerance: 0.25,
nudgeOffset: 0.1,
nudgeMaxRetry: 8,
maxBufferLength: 120,
maxMaxBufferLength: 600,
backBufferLength: 90,
startLevel: -1,
capLevelToPlayerSize: false
};

pkHls = new HlsCtor(hlsOptions);

if (HlsEvents.MANIFEST_PARSED) {
pkHls.on(HlsEvents.MANIFEST_PARSED, function () {
if (isStaleMediaSession(currentMediaToken)) return;
if (isOfficialPikPakTsHls && pikPakMasterTargetName) {
    applyPikPakPreferredHlsLevel(pkHls, pikPakMasterTargetName, pikPakMasterTargetUrl);
}
});
}

pkHls.loadSource(finalPlayUrl);
pkHls.attachMedia(v);

const healthTimer = setInterval(() => {
if (isStaleMediaSession(currentMediaToken) || !pkHls) {
clearInterval(healthTimer);
if (activeHealthTimer === healthTimer) activeHealthTimer = null;
return;
}

if (box.classList.contains('buffering')) {
if (!v._bufferingSince) v._bufferingSince = Date.now();
const isColdStart = v.currentTime < 1.0;
const timeoutThreshold = isColdStart ? 30000 : 20000;

if (Date.now() - v._bufferingSince > timeoutThreshold) {
    console.warn(`[Watchdog] Buffering timeout (${isColdStart ? 'Cold Start' : 'Mid-Stream'}). Forcing error...`);
    clearInterval(healthTimer);
    if (activeHealthTimer === healthTimer) activeHealthTimer = null;
    handleVideoError({ force: true, target: v, mediaToken: currentMediaToken });
}
} else {
v._bufferingSince = null;
}

if (!v.paused && v.currentTime > 0.5) {
if (v.videoWidth === 0 || v.videoHeight === 0) {
        v._blackScreenCount = (v._blackScreenCount || 0) + 1;
}
else {
    const quality = v.getVideoPlaybackQuality ? v.getVideoPlaybackQuality() : null;
    const decodedFrames = quality ? quality.totalVideoFrames : (v.webkitDecodedFrameCount || 0);

    if (decodedFrames === 0) {
        v._blackScreenCount = (v._blackScreenCount || 0) + 1;
    } else {
        v._blackScreenCount = 0;
    }
}

const blackScreenLimit = isOfficialPikPakTsHls ? 8 : 3;

if (v._blackScreenCount > blackScreenLimit) {
    const quality = v.getVideoPlaybackQuality ? v.getVideoPlaybackQuality() : null;
    const decodedFrames = quality ? quality.totalVideoFrames : (v.webkitDecodedFrameCount || 0);

    console.warn(`[Watchdog] Black screen detected.`, {
        time: v.currentTime,
        readyState: v.readyState,
        videoWidth: v.videoWidth,
        videoHeight: v.videoHeight,
        decodedFrames,
        isPikPakTsHls: isOfficialPikPakTsHls,
        hevcCodec: v._pkHevcTsCodec || ''
    });

    clearInterval(healthTimer);
    if (activeHealthTimer === healthTimer) activeHealthTimer = null;
    box.classList.remove('buffering');
    const loader = d.querySelector('.pk-p-loading');
    if (loader) loader.style.display = 'none';
    showSadBox(currentResName || 'HEVC', 'web_unsupported', {
        url: String(currentLink || ''),
        name: currentResName || ''
    });
}
}
}, 1000);
activeHealthTimer = healthTimer;

pkHls.on(HlsEvents.LEVEL_LOADED, function (event, data) {
if (isStaleMediaSession(currentMediaToken)) return;

const details = data && data.details ? data.details : null;
const vCodec = String((details && details.videoCodec) || '').toLowerCase();
if (!vCodec) return;

const isHevcVideo = isLikelyHevcCodec(vCodec);
const isMp4vVideo = vCodec.includes('mp4v');

if (isOfficialPikPakTsHls && isHevcVideo) {
v._pkHevcTsSource = true;
v._pkHevcTsCodec = vCodec;
v._blackScreenCount = 0;
return;
}

if (isMp4vVideo) {
const testMime = `video/mp4; codecs="${vCodec}"`;
if (window.MediaSource && !window.MediaSource.isTypeSupported(testMime)) {
    console.warn(`[VideoCheck] Unsupported legacy video codec detected: ${vCodec}`);
    v.pause();
    showSadBox(vCodec);

    if (pkHls) { pkHls.destroy(); pkHls = null; }
}
}
});

pkHls.on(window.Hls.Events.AUDIO_TRACKS_UPDATED, function (event, data) {
if (isStaleMediaSession(currentMediaToken)) return;
const tracks = data.audioTracks || [];
let detectedBadCodec = null;

for (const track of tracks) {
const codec = (track.codec || '').toLowerCase();
const name = (track.name || '').toLowerCase();

const isSuspicious =
    codec.includes('ac-3') || codec.includes('ec-3') || codec.includes('dts') ||
    name.includes('dts') || name.includes('truehd') || name.includes('atmos');

if (isSuspicious) {
    const testMime = `audio/mp4; codecs="${track.codec || 'ac-3'}"`;
    if (window.MediaSource && !window.MediaSource.isTypeSupported(testMime)) {
        detectedBadCodec = codec || name;
        break;
    }
}
}

if (detectedBadCodec) {
console.warn(`[AudioCheck] Unsupported codec detected: ${detectedBadCodec}`);
v.pause();
showSadBox(detectedBadCodec.toUpperCase());
}
});

const hasHlsPlaybackEvidence = () => {
try {
const hasBuffer = v.buffered && v.buffered.length > 0 && v.buffered.end(v.buffered.length - 1) > 0;
return v.readyState >= 2 ||
        v.currentTime > 0.2 ||
        hasBuffer ||
        (v.videoWidth > 0 && v.videoHeight > 0);
} catch (e) {
return v.readyState >= 2 || v.currentTime > 0.2 || (v.videoWidth > 0 && v.videoHeight > 0);
}
};

pkHls.on(HlsEvents.ERROR, function (event, data) {
if (isStaleMediaSession(currentMediaToken)) return;

const elapsed = Date.now() - hlsLoadStartedAt;
const isColdStart = v.currentTime < 1 && !hasHlsPlaybackEvidence();

if (data.fatal) {
switch (data.type) {
    case HlsErrorTypes.NETWORK_ERROR:
        if (data.response && (data.response.code === 403 || data.response.code === 404 || data.response.code === 401 || data.response.code === 416)) {
            console.warn(`[Hls] Fatal Network Error (${data.response.code}). Triggering rollback.`);
            handleVideoError({ force: true, target: v, mediaToken: currentMediaToken });
        } else {
            try { pkHls.startLoad(); } catch (e) {}
        }
        break;

    case HlsErrorTypes.MEDIA_ERROR:
        console.warn("[Hls] Media error, trying recoverMediaError first.", data.details || data);
        try { pkHls.recoverMediaError(); } catch (e) {}

        setTimeout(() => {
            if (isStaleMediaSession(currentMediaToken)) return;
            if (!pkHls || box.querySelector('.pk-err-dialog')) return;
            if (hasHlsPlaybackEvidence()) return;

            if (isOfficialPikPakTsHls && Date.now() - hlsLoadStartedAt < 12000) {
                try { pkHls.startLoad(); } catch (e) {}
                return;
            }

            handleVideoError({ force: true, target: v, mediaToken: currentMediaToken });
        }, isOfficialPikPakTsHls ? 8000 : 2000);
        break;

    default:
        if (isOfficialPikPakTsHls && isColdStart && elapsed < 15000) {
            console.warn("[Hls] Fatal error during PikPak TS cold start, delaying rollback once.", data.details || data);
            try { pkHls.startLoad(); } catch (e) {}
            return;
        }

        handleVideoError({ force: true, target: v, mediaToken: currentMediaToken });
        break;
}
} else if (data.details === 'bufferStalledError') {
if (isOfficialPikPakTsHls && isColdStart && elapsed < 20000) {
    console.warn("[Hls] Ignored cold-start bufferStalledError for PikPak TS source.");
    try { pkHls.startLoad(); } catch (e) {}
    return;
}

if (!isOfficialPikPakTsHls && v.currentTime < 1 && elapsed > 15000) {
    handleVideoError({ force: true, target: v, mediaToken: currentMediaToken });
}
}
});
} else {
if (isStaleMediaSession(currentMediaToken)) return;

const directUrl = String(url || '');
const directItem = (Array.isArray(qualityList) ? qualityList : []).find(q => {
const qUrl = String(q && (q.link || q.url) || '');
return qUrl && qUrl === directUrl;
});
const isOriginalDirectPlayback = !!(directItem && directItem.isOriginal) || String(currentResName || '') === String(L.str_original);

if (isOriginalDirectPlayback) {
try { v.pause(); } catch (e) {}
try {
v.removeAttribute('src');
v.load();
} catch (e) {}

v.preload = 'auto';
v.src = directUrl;

try { v.load(); } catch (e) {}

} else {
v.src = directUrl;
}

if (startTime > 0) {
const applyDirectStartTime = () => {
if (isStaleMediaSession(currentMediaToken)) return;
try { v.currentTime = startTime; } catch (e) {}
};

if (v.readyState >= 1) {
applyDirectStartTime();
} else {
v.addEventListener('loadedmetadata', applyDirectStartTime, { once: true });
}
}
}
};

let initialData = getBestSource(item);
let currentLink = initialData.src;
let qualityList = initialData.list;
let currentResName = initialData.name;
let lastWorkingLink = null;
let lastWorkingResName = null;
const failedUrls = new Set();
let posterUrl = item.thumbnail_link || '';
if (posterUrl && posterUrl.includes('SIZE_MEDIUM')) {
posterUrl = posterUrl.replace('SIZE_MEDIUM', 'SIZE_LARGE');
}

try {
const linkUrl = new URL(currentLink);
const linkDomain = linkUrl.origin;
if (!document.head.querySelector(`link[href="${linkDomain}"]`)) {
const pc = document.createElement('link');
pc.rel = 'preconnect';
pc.href = linkDomain;
pc.crossOrigin = 'anonymous';
document.head.appendChild(pc);
}
} catch(e) {}

