const resolvePlayableDetailForExternal = async (item) => {
const targetApiId = ((S.offlineMode && item.kind === 'drive#task') || (S.uploadMode && item.file_id)) ? getOfflineReferenceLookupId(item) : item.id;
if (item._isShareItem) return await resolveSharePlayableFile(item);
if (!targetApiId) throw new Error("File ID not ready");
try {
return await apiGet(targetApiId);
} catch (e) {
await markOfflineReferenceMissingFromError(item, e, { source: 'external_detail' });
throw e;
}
};

const cleanExternalPlaybackUrl = (url) => {
let cleanUrl = String(url || '').replace('&ext=.m3u8', '');
if (cleanUrl.includes('ts_downloader') && cleanUrl.includes('url=')) {
try {
const urlParam = new URL(cleanUrl).searchParams.get('url');
if (urlParam) cleanUrl = decodeURIComponent(urlParam);
} catch (e) {}
}
return cleanUrl;
};

function normalizeOriginalVideoDirectUrl(url) {
if (typeof url !== 'string') return '';
const cleanUrl = cleanExternalPlaybackUrl(url).trim();
if (!cleanUrl || /\.m3u8(?:[?#]|$)/i.test(cleanUrl)) return '';
try {
const parsed = new URL(cleanUrl);
if (!/^https?:$/i.test(parsed.protocol)) return '';
if (/\.m3u8$/i.test(parsed.pathname || '')) return '';
return cleanUrl;
} catch (e) {
return '';
}
}

async function tryGetOriginalVideoDownloadUrl(file) {
try {
if (!file || !isVideoLikeItem(file)) return '';
if (file._isShareItem) return normalizeOriginalVideoDirectUrl(file.web_content_link);
let detail = file;
if (!Array.isArray(detail.medias) || !detail.medias.length) {
const targetApiId = ((S.offlineMode && file.kind === 'drive#task') || (S.uploadMode && file.file_id)) ? getOfflineReferenceLookupId(file) : file.id;
if (!targetApiId) return '';
detail = await apiGet(targetApiId);
}
const qualities = generateQualityList(detail);
const original = qualities.find(q => q && q.isOriginal);
return normalizeOriginalVideoDirectUrl(original && original.url);
} catch (e) {
await markOfflineReferenceMissingFromError(file, e, { source: 'downloader_original_link' });
console.warn('[Downloader] Original video link fallback:', e);
return '';
}
}

async function preferOriginalVideoLinksForDownloader(files, options = {}) {
if (!getBoolPref('pk_downloader_prefer_original_video_link', CONF.downloaderPreferOriginalVideoLink)) return files;
const list = Array.isArray(files) ? files : [];
const videoIndexes = [];
for (let i = 0; i < list.length; i++) {
if (isVideoLikeItem(list[i])) videoIndexes.push(i);
}
if (!videoIndexes.length) return list;

const isRunning = typeof options.isRunning === 'function' ? options.isRunning : () => true;
const onProgress = typeof options.onProgress === 'function' ? options.onProgress : null;
const cache = new Map();
const queue = videoIndexes.slice();
const total = queue.length;
let done = 0;
const limit = Math.min(4, total);

if (onProgress) onProgress(done, total);

const getCacheKey = (file) => String((file && (file.id || file.file_id || file.gcid || file.hash || file.web_content_link)) || '');
const getCachedUrl = async (file) => {
const key = getCacheKey(file);
if (!key) return await tryGetOriginalVideoDownloadUrl(file);
if (!cache.has(key)) cache.set(key, tryGetOriginalVideoDownloadUrl(file));
const url = await cache.get(key);
cache.set(key, url || '');
return url || '';
};

const worker = async () => {
while (queue.length && isRunning()) {
const idx = queue.shift();
const file = list[idx];
try {
    const originalUrl = await getCachedUrl(file);
    if (originalUrl) list[idx] = Object.assign({}, file, { web_content_link: originalUrl });
} catch (e) {
    console.warn('[Downloader] Original video link skipped:', e);
} finally {
    done++;
    if (onProgress) onProgress(done, total);
}
}
};

await Promise.all(Array.from({ length: limit }, worker));
return list;
}

function getM3UExportItemById(id) {
if (!id) return null;
return (S.shareParseInsightItemMap && S.shareParseInsightItemMap.get(id)) || (S.shareParseItemMap && S.shareParseItemMap.get(id)) || (S.itemMap && S.itemMap.get(id)) || (S.items || []).find(it => it && it.id === id) || null;
}

function isM3UExportVideoItem(item) {
if (!item || item.isHeader || item.kind === 'drive#folder') return false;
if (S.offlineMode && item.kind === 'drive#task' && item.phase !== 'PHASE_TYPE_COMPLETE') return false;
if (S.uploadMode && item.status !== 'DONE') return false;
return isVideoLikeItem(item);
}

function getM3UExportSelectedVideos() {
const selected = new Set(S.getSelectedIds());
if (!selected.size) return [];
const out = [];
const seen = new Set();
const list = Array.isArray(S.display) ? S.display : [];
for (let i = 0; i < list.length; i++) {
const displayItem = list[i];
const id = displayItem && displayItem.id;
if (!id || seen.has(id) || !selected.has(id)) continue;
const item = getM3UExportItemById(id) || displayItem;
if (!isM3UExportVideoItem(item)) continue;
seen.add(id);
out.push(item);
}
return out;
}

function escapeM3UInfoText(s) { return String(s || '').replace(/[\r\n]+/g, ' ').trim() || 'video'; }

function downloadM3UText(text, fileName) {
const blob = new Blob([text], { type: 'audio/x-mpegurl;charset=utf-8' });
const url = URL.createObjectURL(blob);
const a = document.createElement('a');
a.href = url;
a.download = fileName || 'PikPak_Selected_Videos.m3u';
document.body.appendChild(a);
a.click();
setTimeout(() => {
URL.revokeObjectURL(url);
a.remove();
}, 0);
}

function getM3UExportFileName() {
const pad = n => String(n).padStart(2, '0');
const d = new Date();
const ts = `${d.getFullYear()}${pad(d.getMonth() + 1)}${pad(d.getDate())}_${pad(d.getHours())}${pad(d.getMinutes())}${pad(d.getSeconds())}`;
const pathName = (S.path && S.path.length ? S.path[S.path.length - 1].name : '') || 'PikPak';
const safe = String(pathName).replace(/[\\/:*?"<>|\r\n]+/g, '_').slice(0, 60) || 'PikPak';
return `${safe}_M3U_${ts}.m3u`;
}

function formatM3UExportProgress(done, total) {
return (getStrings().msg_m3u_export_progress).replace('{done}', done).replace('{total}', total);
}

