const heroBox = m.querySelector('.pk-magnet-hero');
let heroShotIndex = -1;
let heroReady = false;
const failedHeroShots = new Set();
const getShotThumb = (idx) => m.querySelector(`.pk-magnet-thumb-wrap[data-shot-index="${idx}"]`);
const getThumbSrc = (thumb) => thumb?.dataset?.shotSrc || thumb?.querySelector('img')?.getAttribute('src') || '';
const showHeroEmpty = () => {
if (!heroBox) return;
heroReady = false;
heroBox.innerHTML = `<div class="pk-magnet-empty">${esc(TXT.str_no_preview)}</div>`;
};
const bindHeroImg = (img) => {
if (!img) return;
img.addEventListener('dragstart', e => e.preventDefault());
img.onload = () => { heroReady = true; };
img.onerror = () => {
const idx = Number(img.dataset.shotIndex);
if (Number.isFinite(idx) && idx >= 0) failedHeroShots.add(idx);
heroReady = false;
tryNextHeroShot();
};
};
const setHeroShot = (src, thumb, idx) => {
if (!heroBox || !src) return;
const explicitIdx = Number(idx);
const thumbIdx = Number(thumb?.dataset?.shotIndex);
const shotIdx = Number.isFinite(explicitIdx) && explicitIdx >= 0 ? explicitIdx : (Number.isFinite(thumbIdx) && thumbIdx >= 0 ? thumbIdx : shots.findIndex(shot => shot && shot.src === src));
heroShotIndex = shotIdx;
heroReady = false;
const img = document.createElement('img');
img.alt = '';
img.draggable = false;
img.referrerPolicy = 'no-referrer';
if (shotIdx >= 0) img.dataset.shotIndex = String(shotIdx);
bindHeroImg(img);
heroBox.replaceChildren(img);
img.src = src;
m.querySelectorAll('.pk-magnet-thumb-wrap').forEach(x => x.classList.remove('active'));
const activeThumb = thumb || getShotThumb(shotIdx);
if (activeThumb) activeThumb.classList.add('active');
};
const tryNextHeroShot = () => {
if (!shots.length) {
showHeroEmpty();
return false;
}
for (let i = Math.max(heroShotIndex + 1, 0); i < shots.length; i++) {
const shot = shots[i];
if (shot && shot.src && !failedHeroShots.has(i)) {
setHeroShot(shot.src, getShotThumb(i), i);
return true;
}
}
for (let i = 0; i < shots.length; i++) {
const shot = shots[i];
if (shot && shot.src && !failedHeroShots.has(i)) {
setHeroShot(shot.src, getShotThumb(i), i);
return true;
}
}
showHeroEmpty();
return false;
};
const heroNeedsFallback = () => {
if (!heroBox) return false;
const heroImg = heroBox.querySelector('img');
if (!heroImg) return true;
if (heroBox.querySelector('.pk-magnet-empty')) return true;
if (heroImg.complete && heroImg.naturalWidth === 0) {
const idx = Number(heroImg.dataset.shotIndex);
if (Number.isFinite(idx) && idx >= 0) failedHeroShots.add(idx);
return true;
}
return false;
};
const ensureHeroShot = () => {
if (!heroBox || !heroNeedsFallback()) return;
const thumbs = Array.from(m.querySelectorAll('.pk-magnet-thumb-wrap'));
const usableThumb = thumbs.find(thumb => {
const img = thumb.querySelector('img');
return !img || !img.complete || img.naturalWidth > 0;
});
if (usableThumb) {
setHeroShot(getThumbSrc(usableThumb), usableThumb);
return;
}
tryNextHeroShot();
};

m.querySelectorAll('.pk-magnet-thumb-wrap').forEach(thumb => {
const img = thumb.querySelector('img');
thumb.addEventListener('dragstart', e => e.preventDefault());
thumb.addEventListener('click', () => setHeroShot(getThumbSrc(thumb), thumb));
if (img) {
img.addEventListener('error', () => {
const wasActive = thumb.classList.contains('active');
const idx = Number(thumb.dataset.shotIndex);
if (Number.isFinite(idx) && idx >= 0) failedHeroShots.add(idx);
thumb.remove();
if (wasActive && !heroReady) ensureHeroShot();
});
}
});

ensureHeroShot();
[80, 300, 900].forEach(ms => setTimeout(ensureHeroShot, ms));

