const getDownloaderPreferOriginalVideoLinkChecked = () => {
const input = downloaderPreferOriginalVideoLinkInputs.find(el => el && el.offsetParent !== null) || downloaderPreferOriginalVideoLinkInputs[0];
return input ? !!input.checked : CONF.downloaderPreferOriginalVideoLink;
};
const isDownloaderPreferOriginalVideoLinkCustomized = () => getDownloaderPreferOriginalVideoLinkChecked() !== CONF.downloaderPreferOriginalVideoLink;
const keepStructureInputs = Array.from(m.querySelectorAll('#set_aria_keep_structure,#set_gopeed_keep_structure,#set_abdm_keep_structure,#set_idm_bat_keep_structure'));
const getDownloaderKeepStructureChecked = () => {
const input = keepStructureInputs.find(el => el && el.offsetParent !== null) || keepStructureInputs[0];
return input ? !!input.checked : CONF.aria2KeepFolderStructure;
};
const syncDownloaderKeepStructureInputs = (checked) => keepStructureInputs.forEach(input => { if (input) input.checked = !!checked; });
const isDownloaderKeepStructureCustomized = () => getDownloaderKeepStructureChecked() !== CONF.aria2KeepFolderStructure;
const updateAriaGroupBorder = () => { if (ariaGroup) ariaGroup.classList.toggle('pk-inner-active', !!(ariaInp.value.trim() || ariaTok.value.trim() || ariaDir.value.trim() || isDownloaderKeepStructureCustomized() || isDownloaderPreferOriginalVideoLinkCustomized())); };
const updateGopeedGroupBorder = () => { if (gopeedGroup) gopeedGroup.classList.toggle('pk-inner-active', !!(gopeedInp.value.trim() || gopeedTok.value.trim() || gopeedDir.value.trim() || isDownloaderKeepStructureCustomized() || isDownloaderPreferOriginalVideoLinkCustomized())); };
const updateAbdmGroupBorder = () => { if (abdmGroup) abdmGroup.classList.toggle('pk-inner-active', !!(abdmInp.value.trim() || abdmDir.value.trim() || isDownloaderKeepStructureCustomized() || isDownloaderPreferOriginalVideoLinkCustomized())); };
const updateIdmGroupBorder = () => { if (idmGroup) idmGroup.classList.toggle('pk-inner-active', !!(selectedIdmExportMode !== CONF.idmExportMode || selectedIdmUrlExportType !== CONF.idmUrlExportType || (idmExePath && idmExePath.value.trim()) || (idmBatRoot && idmBatRoot.value.trim()) || isDownloaderKeepStructureCustomized() || isDownloaderPreferOriginalVideoLinkCustomized())); };
