let gopeedTokenVisible = false;

const updateIdmExportModeVisibility = () => {
const isBat = normalizeIdmExportMode(selectedIdmExportMode) === 'bat';
if (idmUrlGroup) idmUrlGroup.style.display = isBat ? 'none' : 'flex';
if (idmBatGroup) idmBatGroup.style.display = isBat ? 'flex' : 'none';
updateIdmGroupBorder();
};

const updateDownloaderSettingsVisibility = () => {
const type = normalizeDownloaderType(selectedDownloaderType);
const rpcType = 'aria2';
if (ariaGroup) ariaGroup.style.display = type === 'aria2' ? 'block' : 'none';
if (gopeedGroup) gopeedGroup.style.display = type === 'gopeed' ? 'block' : 'none';
if (abdmGroup) abdmGroup.style.display = type === 'abdm' ? 'block' : 'none';
if (idmGroup) idmGroup.style.display = type === 'idm' ? 'block' : 'none';
if (ariaInp) ariaInp.placeholder = getDefaultRpcUrlForDownloader(rpcType);
if (ariaCfgLabel) ariaCfgLabel.textContent = formatDownloaderText(L.label_downloader_config, rpcType);
if (ariaUrlLabel) ariaUrlLabel.textContent = formatDownloaderText(L.label_downloader_url, rpcType);
if (ariaTokenLabel) ariaTokenLabel.textContent = formatDownloaderText(L.label_downloader_token, rpcType);
if (ariaDirLabel) ariaDirLabel.textContent = formatDownloaderText(L.label_downloader_dir, rpcType);
clearTimeout(ariaTimer);
clearTimeout(gopeedTimer);
clearTimeout(abdmTimer);
if (type !== 'aria2') {
ariaDot.className = 'pk-aria-dot';
ariaTxt.textContent = L.lbl_downloader_status;
}
if (type !== 'gopeed') {
gopeedDot.className = 'pk-aria-dot';
gopeedTxt.textContent = L.lbl_downloader_status;
}
if (type !== 'abdm') {
abdmDot.className = 'pk-aria-dot';
abdmTxt.textContent = L.lbl_downloader_status;
}
if (type === 'idm') updateIdmExportModeVisibility();
};

const runAriaTest = async () => {
const url = ariaInp.value.trim();
const token = ariaTok.value.trim();
const showTip = () => showAlert(L.tip_mixed_content, L.lbl_downloader_status);

if (!url) {
ariaDot.className = 'pk-aria-dot';
ariaTxt.textContent = L.lbl_downloader_status;
ariaBox.onclick = showTip;
ariaBox.style.cursor = 'pointer';
return;
}

ariaDot.className = 'pk-aria-dot wait';
ariaTxt.textContent = L.str_connecting;
ariaBox.onclick = showTip;
ariaBox.style.cursor = 'pointer';

const testUrl = normalizeAriaRpcUrl(url);
const payload = { jsonrpc: '2.0', method: 'aria2.getVersion', id: 'pk_live_test', params: buildAriaRpcParams(token) };

try {
await aria2RpcRequest(testUrl, payload, 3000);
ariaDot.className = 'pk-aria-dot ok';
ariaTxt.textContent = L.str_connected;
ariaBox.onclick = null;
ariaBox.style.cursor = 'default';
} catch (e) {
ariaDot.className = 'pk-aria-dot err';
ariaTxt.textContent = L.str_conn_fail;
ariaBox.onclick = showTip;
ariaBox.style.cursor = 'pointer';
}
};

const debouncedTest = () => {
clearTimeout(ariaTimer);
ariaTimer = setTimeout(runAriaTest, 600);
};

const runGopeedTest = async () => {
const url = gopeedInp.value.trim();
const token = gopeedTok.value.trim();
const showTip = (msg = L.desc_gopeed_setup) => showAlert(msg, L.lbl_downloader_status);

if (!url) {
gopeedDot.className = 'pk-aria-dot';
gopeedTxt.textContent = L.lbl_downloader_status;
gopeedBox.onclick = () => showTip();
gopeedBox.style.cursor = 'pointer';
return;
}

gopeedDot.className = 'pk-aria-dot wait';
gopeedTxt.textContent = L.str_connecting;
gopeedBox.onclick = () => showTip();
gopeedBox.style.cursor = 'pointer';

try {
await testGopeedConnection(normalizeGopeedApiUrl(url), token, 3000);
gopeedDot.className = 'pk-aria-dot ok';
gopeedTxt.textContent = L.str_connected;
gopeedBox.onclick = null;
gopeedBox.style.cursor = 'default';
} catch (e) {
gopeedDot.className = 'pk-aria-dot err';
gopeedTxt.textContent = L.str_conn_fail;
gopeedBox.onclick = () => showTip();
gopeedBox.style.cursor = 'pointer';
}
};

const debouncedGopeedTest = () => {
clearTimeout(gopeedTimer);
gopeedTimer = setTimeout(runGopeedTest, 600);
};

const runAbdmTest = async () => {
const url = abdmInp.value.trim();
const showTip = () => showAlert(L.desc_abdm_setup, L.lbl_downloader_status);

if (!url) {
abdmDot.className = 'pk-aria-dot';
abdmTxt.textContent = L.lbl_downloader_status;
abdmBox.onclick = showTip;
abdmBox.style.cursor = 'pointer';
return;
}

abdmDot.className = 'pk-aria-dot wait';
abdmTxt.textContent = L.str_connecting;
abdmBox.onclick = showTip;
abdmBox.style.cursor = 'pointer';

let testUrl = '';
try {
const parsed = new URL(url);
if (!/^https?:$/i.test(parsed.protocol) || !parsed.hostname) throw new Error('Invalid ABDM API URL');
testUrl = normalizeAbdmApiUrl(url);
if (!testUrl) throw new Error('Invalid ABDM API URL');
} catch (e) {
abdmDot.className = 'pk-aria-dot err';
abdmTxt.textContent = L.str_conn_fail;
abdmBox.onclick = showTip;
abdmBox.style.cursor = 'pointer';
return;
}

try {
await testAbdmConnection(testUrl, 3000);
abdmDot.className = 'pk-aria-dot ok';
abdmTxt.textContent = L.str_connected;
abdmBox.onclick = null;
abdmBox.style.cursor = 'default';
} catch (e) {
abdmDot.className = 'pk-aria-dot err';
abdmTxt.textContent = L.str_conn_fail;
abdmBox.onclick = showTip;
abdmBox.style.cursor = 'pointer';
}
};

const debouncedAbdmTest = () => {
clearTimeout(abdmTimer);
abdmTimer = setTimeout(runAbdmTest, 600);
};

const testActiveDownloaderConnection = () => {
const type = normalizeDownloaderType(selectedDownloaderType);
if (type === 'aria2') {
clearTimeout(ariaTimer);
runAriaTest();
} else if (type === 'gopeed') {
clearTimeout(gopeedTimer);
runGopeedTest();
} else if (type === 'abdm') {
clearTimeout(abdmTimer);
runAbdmTest();
}
};

