async function syncGlobalStarredStatus() {
let nextToken = null;
try {
const latestStarredIds = new Set();

do {
const filter = encodeURIComponent('{"starred":{"eq":true},"trashed":{"eq":false}}');
const url = `https://api-drive.mypikpak.com/drive/v1/files?filters=${filter}&limit=1000${nextToken ? `&page_token=${nextToken}` : ''}`;

const res = await fetch(url, { headers: getHeaders() });
if (!res.ok) break;

const data = await res.json();
if (data.files) {
data.files.forEach(f => latestStarredIds.add(f.id));
}
nextToken = data.next_page_token;
} while (nextToken);

S.pendingMap.forEach((targetStatus, id) => {
if (targetStatus) {
latestStarredIds.add(id);
} else {
latestStarredIds.delete(id);
}
});

if (latestStarredIds.size > 0 || S.items.length > 0) {
S.starredSet = latestStarredIds;
if (typeof renderVisible === 'function') renderVisible();
}
} catch (e) {}
}

const fmtTransferQuotaSize = (v) => {
let n = Number(v || 0);
if (!Number.isFinite(n) || n <= 0) return '0.00 KB';

const units = ['B', 'KB', 'MB', 'GB', 'TB'];
let i = 0;

while (n >= 1024 && i < units.length - 1) {
n /= 1024;
i++;
}

const truncated = Math.floor((n + Number.EPSILON) * 100) / 100;
return `${truncated.toFixed(2)} ${units[i]}`;
};

const buildTransferQuotaRowHtml = (label, quota, extraInfo = '') => {
const total = Number((quota && quota.total_assets) || 0);
const used = Number((quota && (quota.assets || quota.size)) || 0);
const pct = total > 0 ? Math.max(0, Math.min(100, (used / total) * 100)) : 0;
return `
<div style="display:flex; flex-direction:column; gap:var(--pk-transfer-quota-row-gap,10px); margin-top:var(--pk-transfer-quota-row-mt,28px);">
<div style="font-size:16px; font-weight:700; color:var(--pk-fg);">${label}</div>
<div style="font-size:14px; color:var(--pk-fg); opacity:0.95;">${fmtTransferQuotaSize(total)}</div>
<div style="width:100%; height:6px; background:var(--pk-hl); border-radius:999px; overflow:hidden; position:relative;">
<div style="position:absolute; left:0; top:0; height:100%; width:${pct}%; background:var(--pk-pri); border-radius:999px;"></div>
</div>
<div style="display:flex; justify-content:space-between; gap:12px; font-size:14px; color:var(--pk-fg); opacity:0.75;">
<span>${L.transfer_quota_used_total.replace('{u}', fmtTransferQuotaSize(used)).replace('{t}', fmtTransferQuotaSize(total))}</span>
<span style="text-align:right;">${extraInfo || ''}</span>
</div>
</div>
`;
};

